import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type SlotType = 'task' | 'decision' | 'operation';

export interface ProcessSlot {
  id: string;
  label: string;
  type: SlotType;
}

export interface ProcessNode {
  id: string;
  title: string;
  description: string;
  x: number;
  y: number;
  width: number;
  height: number;
  color: string;
  slots: ProcessSlot[];
  layer: number; // For horizontal positioning
  status: 'idle' | 'running' | 'success' | 'failed';
}

export interface Connection {
  id: string;
  sourceNodeId: string;
  sourceSlotId: string;
  targetNodeId: string;
  targetSlotId: string;
  biDirectional: boolean;
  label?: string;
}

export interface Resource {
  id: string;
  name: string;
  type: string;
  cost: number;
  available: boolean;
}

export interface NodeInsights {
  nodeId: string;
  requirements: string[];
  resources: Resource[];
  summary: string;
  executionStyle: string;
}

export type PageView = 'editor' | 'insights' | 'report' | 'simulation';

import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeProcessData = async (nodeTitle: string, rawText: string, imageData?: string) => {
  const ai = getAI();
  const prompt = `Analyze this process step: "${nodeTitle}". 
  Context Data: ${rawText}
  Extract:
  1. Detailed requirements (costs, resources, time, risks).
  2. Available resources matching this step.
  3. A summary of execution strategy.
  4. Decision conditions if applicable.`;

  const contents: any[] = [{ text: prompt }];
  if (imageData) {
    contents.push({
      inlineData: {
        mimeType: 'image/jpeg',
        data: imageData.split(',')[1] || imageData
      }
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: contents },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            requirements: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            resources: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  type: { type: Type.STRING },
                  cost: { type: Type.NUMBER },
                  available: { type: Type.BOOLEAN }
                }
              }
            },
            summary: { type: Type.STRING },
            executionStyle: { type: Type.STRING }
          }
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return null;
  }
};

import React, { useState, useCallback, useEffect } from 'react';
import { PageView, ProcessNode, Connection, NodeInsights } from './types';
import Sidebar from './components/Sidebar';
import Editor from './components/Editor';
import Insights from './components/Insights';
import Report from './components/Report';
import Simulation from './components/Simulation';

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageView>('editor');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [projectTitle, setProjectTitle] = useState('New Process Master Plan');

  // State for Editor
  const [nodes, setNodes] = useState<ProcessNode[]>([]);
  const [connections, setConnections] = useState<Connection[]>([]);
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);

  // State for Insights & Knowledge Base
  const [insightsMap, setInsightsMap] = useState<Record<string, NodeInsights>>({});

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const addNode = useCallback((x: number, y: number, layer: number) => {
    const newNode: ProcessNode = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Step',
      description: 'Step Description',
      x,
      y,
      width: 220,
      height: 120,
      color: '#ffffff',
      slots: [
        { id: Math.random().toString(36).substr(2, 9), label: 'Primary Task', type: 'task' }
      ],
      layer,
      status: 'idle'
    };
    setNodes(prev => [...prev, newNode]);
  }, []);

  const updateNode = useCallback((id: string, updates: Partial<ProcessNode>) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, ...updates } : n));
  }, []);

  const addConnection = useCallback((conn: Connection) => {
    setConnections(prev => [...prev, conn]);
  }, []);

  const renderPage = () => {
    switch (activePage) {
      case 'editor':
        return (
          <Editor 
            nodes={nodes} 
            connections={connections} 
            onAddNode={addNode} 
            onUpdateNode={updateNode} 
            onAddConnection={addConnection}
            projectTitle={projectTitle}
            setProjectTitle={setProjectTitle}
            selectedNodeId={selectedNodeId}
            setSelectedNodeId={setSelectedNodeId}
          />
        );
      case 'insights':
        return (
          <Insights 
            nodes={nodes}
            selectedNodeId={selectedNodeId}
            insightsMap={insightsMap}
            setInsightsMap={setInsightsMap}
          />
        );
      case 'simulation':
        return (
          <Simulation 
            nodes={nodes} 
            connections={connections}
            insightsMap={insightsMap}
            setNodes={setNodes}
          />
        );
      case 'report':
        return (
          <Report 
            nodes={nodes} 
            connections={connections} 
            insightsMap={insightsMap}
            projectTitle={projectTitle}
          />
        );
      default:
        return <Editor nodes={nodes} connections={connections} onAddNode={addNode} onUpdateNode={updateNode} onAddConnection={addConnection} projectTitle={projectTitle} setProjectTitle={setProjectTitle} selectedNodeId={selectedNodeId} setSelectedNodeId={setSelectedNodeId} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 text-slate-900 overflow-hidden">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={toggleSidebar} 
        activePage={activePage} 
        setActivePage={setActivePage} 
      />

      <main className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen ? 'ml-0' : 'ml-0'}`}>
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-10">
          <div className="flex items-center gap-4">
            <button 
              onClick={toggleSidebar}
              className="p-2 hover:bg-slate-100 rounded-lg transition-colors"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
              {projectTitle}
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="px-3 py-1 bg-blue-50 text-blue-600 rounded-full text-xs font-semibold">
              v1.0.4 Stable
            </div>
            <div className="w-10 h-10 rounded-full bg-slate-200 overflow-hidden">
              <img src="https://picsum.photos/40/40" alt="Avatar" />
            </div>
          </div>
        </header>

        <div className="flex-1 relative overflow-auto">
          {renderPage()}
        </div>
      </main>
    </div>
  );
};

export default App;

