import React, { useState, useRef, useEffect } from 'react';
import { ProcessNode, Connection, SlotType } from '../types';

interface EditorProps {
  nodes: ProcessNode[];
  connections: Connection[];
  onAddNode: (x: number, y: number, layer: number) => void;
  onUpdateNode: (id: string, updates: Partial<ProcessNode>) => void;
  onAddConnection: (conn: Connection) => void;
  projectTitle: string;
  setProjectTitle: (val: string) => void;
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
}

const Editor: React.FC<EditorProps> = ({ 
  nodes, connections, onAddNode, onUpdateNode, onAddConnection, 
  projectTitle, setProjectTitle, selectedNodeId, setSelectedNodeId 
}) => {
  const [isConnecting, setIsConnecting] = useState<{ nodeId: string, slotId: string } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);

  const handleCanvasClick = (e: React.MouseEvent) => {
    if (e.target === canvasRef.current || (e.target as HTMLElement).classList.contains('canvas-grid')) {
      const rect = canvasRef.current?.getBoundingClientRect();
      if (rect) {
        const x = e.clientX - rect.left;
        const y = e.clientY - rect.top;
        const layer = Math.floor(y / 200);
        onAddNode(x - 110, y - 60, layer);
        setSelectedNodeId(null);
      }
    }
  };

  const handleSlotClick = (nodeId: string, slotId: string) => {
    if (!isConnecting) {
      setIsConnecting({ nodeId, slotId });
    } else {
      if (isConnecting.nodeId !== nodeId) {
        onAddConnection({
          id: Math.random().toString(36).substr(2, 9),
          sourceNodeId: isConnecting.nodeId,
          sourceSlotId: isConnecting.slotId,
          targetNodeId: nodeId,
          targetSlotId: slotId,
          biDirectional: false
        });
      }
      setIsConnecting(null);
    }
  };

  const addSlot = (nodeId: string, type: SlotType) => {
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      onUpdateNode(nodeId, {
        slots: [...node.slots, { id: Math.random().toString(36).substr(2, 9), label: `New ${type}`, type }]
      });
    }
  };

  return (
    <div className="flex flex-col h-full">
      {/* Top Formatting Toolbar */}
      <div className="bg-white border-b border-slate-200 p-2 flex items-center gap-4 shadow-sm">
        <div className="flex items-center gap-1 border-r pr-4">
          <input 
            type="text" 
            value={projectTitle}
            onChange={(e) => setProjectTitle(e.target.value)}
            className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500 w-64"
          />
        </div>
        <div className="flex items-center gap-2">
          <button className="p-2 hover:bg-slate-100 rounded" title="Text Bold"><b>B</b></button>
          <button className="p-2 hover:bg-slate-100 rounded" title="Text Italic"><i>I</i></button>
          <select className="text-sm border border-slate-200 rounded px-2 py-1 bg-slate-50">
            <option>12px</option>
            <option>14px</option>
            <option>16px</option>
          </select>
          <div className="w-[1px] h-6 bg-slate-200 mx-1"></div>
          <button className="flex items-center gap-2 px-3 py-1 bg-blue-600 text-white rounded text-sm hover:bg-blue-700 transition-colors">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
            Import Template
          </button>
        </div>
      </div>

      <div 
        ref={canvasRef}
        onClick={handleCanvasClick}
        className="flex-1 relative bg-slate-100 overflow-auto canvas-grid"
        style={{
          backgroundImage: 'radial-gradient(circle, #cbd5e1 1px, transparent 1px)',
          backgroundSize: '24px 24px'
        }}
      >
        {/* Horizontal Layers with Labels */}
        {[0, 1, 2, 3, 4, 5].map(i => (
          <div key={i} className="absolute w-full border-b border-slate-300 pointer-events-none" style={{ top: i * 200, height: 200 }}>
            <span className="absolute right-4 top-4 text-xs font-bold text-slate-400 bg-white/80 px-2 py-1 rounded border border-slate-200">LAYER {i + 1}</span>
          </div>
        ))}

        {/* SVG layer for Connections */}
        <svg className="absolute inset-0 w-full h-full pointer-events-none" style={{ minWidth: 2000, minHeight: 2000 }}>
          <defs>
            <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orientation="auto">
              <polygon points="0 0, 10 3.5, 0 7" fill="#64748b" />
            </marker>
          </defs>
          {connections.map(conn => {
            const source = nodes.find(n => n.id === conn.sourceNodeId);
            const target = nodes.find(n => n.id === conn.targetNodeId);
            if (!source || !target) return null;

            const x1 = source.x + source.width;
            const y1 = source.y + 40 + (source.slots.findIndex(s => s.id === conn.sourceSlotId) * 24);
            const x2 = target.x;
            const y2 = target.y + 40 + (target.slots.findIndex(s => s.id === conn.targetSlotId) * 24);

            return (
              <g key={conn.id}>
                <path 
                  d={`M ${x1} ${y1} C ${x1 + 50} ${y1}, ${x2 - 50} ${y2}, ${x2} ${y2}`}
                  stroke="#64748b"
                  strokeWidth="2"
                  fill="none"
                  markerEnd="url(#arrowhead)"
                />
              </g>
            );
          })}
        </svg>

        {/* Nodes */}
        {nodes.map(node => (
          <div
            key={node.id}
            onClick={(e) => { e.stopPropagation(); setSelectedNodeId(node.id); }}
            className={`absolute bg-white rounded-lg border-2 shadow-sm transition-all group flex flex-col ${selectedNodeId === node.id ? 'border-blue-500 ring-4 ring-blue-500/10 scale-[1.02]' : 'border-slate-300 hover:border-slate-400'}`}
            style={{ 
              left: node.x, 
              top: node.y, 
              width: node.width,
              minHeight: node.height,
              zIndex: selectedNodeId === node.id ? 20 : 10 
            }}
          >
            {/* Header / Title Slot */}
            <div className="bg-slate-50 border-b border-slate-200 px-3 py-2 flex items-center justify-between">
              <input 
                className="font-bold text-sm bg-transparent w-full focus:outline-none"
                value={node.title}
                onChange={(e) => onUpdateNode(node.id, { title: e.target.value })}
              />
              <div className="flex gap-1 opacity-0 group-hover:opacity-100">
                 <button 
                  onClick={(e) => { e.stopPropagation(); addSlot(node.id, 'task'); }}
                  className="p-1 hover:bg-slate-200 rounded text-slate-500"
                  title="Add Task Slot"
                >
                  +
                </button>
              </div>
            </div>

            {/* Content / Slots */}
            <div className="p-3 space-y-2">
              <textarea 
                className="text-[11px] text-slate-500 w-full resize-none h-10 border-none bg-transparent focus:outline-none"
                placeholder="Brief description..."
                value={node.description}
                onChange={(e) => onUpdateNode(node.id, { description: e.target.value })}
              />
              <div className="space-y-1">
                {node.slots.map(slot => (
                  <div 
                    key={slot.id} 
                    className="flex items-center justify-between text-[11px] group/slot"
                    onClick={(e) => e.stopPropagation()}
                  >
                    <div className="flex items-center gap-2">
                      <div className={`w-2 h-2 rounded-full ${slot.type === 'task' ? 'bg-blue-400' : slot.type === 'decision' ? 'bg-amber-400' : 'bg-emerald-400'}`}></div>
                      <input 
                        className="bg-transparent hover:bg-slate-50 focus:outline-none border-none py-0.5 px-1"
                        value={slot.label}
                        onChange={(e) => {
                          const newSlots = node.slots.map(s => s.id === slot.id ? { ...s, label: e.target.value } : s);
                          onUpdateNode(node.id, { slots: newSlots });
                        }}
                      />
                    </div>
                    <button 
                      onClick={() => handleSlotClick(node.id, slot.id)}
                      className={`w-4 h-4 rounded-full border border-slate-300 flex items-center justify-center transition-all ${isConnecting?.slotId === slot.id ? 'bg-blue-500 border-blue-500 text-white' : 'bg-white hover:bg-slate-100'}`}
                    >
                      <div className="w-1.5 h-1.5 bg-slate-400 rounded-full"></div>
                    </button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Node Control Legend */}
      <div className="p-3 bg-white border-t flex justify-between items-center text-xs text-slate-500">
        <div className="flex gap-4">
          <div className="flex items-center gap-1"><div className="w-2 h-2 bg-blue-400 rounded-full"></div> Tasks</div>
          <div className="flex items-center gap-1"><div className="w-2 h-2 bg-amber-400 rounded-full"></div> Decisions</div>
          <div className="flex items-center gap-1"><div className="w-2 h-2 bg-emerald-400 rounded-full"></div> Operations</div>
        </div>
        <p>Click empty space to add step. Connect slots by clicking the dots.</p>
      </div>
    </div>
  );
};

export default Editor;

import React, { useState } from 'react';
import { ProcessNode, NodeInsights } from '../types';
import { analyzeProcessData } from '../services/geminiService';

interface InsightsProps {
  nodes: ProcessNode[];
  selectedNodeId: string | null;
  insightsMap: Record<string, NodeInsights>;
  setInsightsMap: React.Dispatch<React.SetStateAction<Record<string, NodeInsights>>>;
}

const Insights: React.FC<InsightsProps> = ({ nodes, selectedNodeId, insightsMap, setInsightsMap }) => {
  const [inputText, setInputText] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [uploadedFiles, setUploadedFiles] = useState<File[]>([]);

  const currentNode = nodes.find(n => n.id === selectedNodeId);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      setUploadedFiles(prev => [...prev, ...Array.from(e.target.files!)]);
    }
  };

  const handleAnalyze = async () => {
    if (!currentNode) return;
    setIsAnalyzing(true);

    // Simulate reading files and combining text
    const context = `Node: ${currentNode.title}. Description: ${currentNode.description}. User Input: ${inputText}. Files: ${uploadedFiles.map(f => f.name).join(', ')}`;

    const result = await analyzeProcessData(currentNode.title, context);
    if (result) {
      setInsightsMap(prev => ({
        ...prev,
        [currentNode.id]: {
          nodeId: currentNode.id,
          ...result
        }
      }));
    }
    setIsAnalyzing(false);
  };

  if (!selectedNodeId) {
    return (
      <div className="h-full flex items-center justify-center text-slate-400 flex-col gap-4">
