import React, { useState, useEffect, useCallback } from 'react';
import { ProcessNode, Connection, NodeInsights } from '../types';

interface SimulationProps {
  nodes: ProcessNode[];
  connections: Connection[];
  insightsMap: Record<string, NodeInsights>;
  setNodes: React.Dispatch<React.SetStateAction<ProcessNode[]>>;
}

const Simulation: React.FC<SimulationProps> = ({ nodes, connections, insightsMap, setNodes }) => {
  const [isRunning, setIsRunning] = useState(false);
  const [activeNodeIndex, setActiveNodeIndex] = useState(-1);
  const [logs, setLogs] = useState<string[]>([]);

  const startSim = () => {
    setIsRunning(true);
    setLogs(["Initializing simulation..."]);
    setActiveNodeIndex(0);
    // Reset all nodes to idle
    setNodes(prev => prev.map(n => ({ ...n, status: 'idle' })));
  };

  const stopSim = () => {
    setIsRunning(false);
    setActiveNodeIndex(-1);
  };

  useEffect(() => {
    if (!isRunning || activeNodeIndex >= nodes.length) {
      if (activeNodeIndex >= nodes.length) {
        setIsRunning(false);
        setLogs(prev => [...prev, "Simulation completed successfully."]);
      }
      return;
    }

    const timer = setTimeout(() => {
      const currentNode = nodes[activeNodeIndex];
      const insights = insightsMap[currentNode.id];

      setLogs(prev => [...prev, `Evaluating step: ${currentNode.title}...`]);

      // Verification logic: does it have insights/requirements?
      const success = !!insights && insights.resources.length > 0;

      setNodes(prev => prev.map(n => n.id === currentNode.id ? { ...n, status: success ? 'success' : 'failed' } : n));

      if (success) {
        setLogs(prev => [...prev, `✓ Step ${currentNode.title} verified. Resources available.`]);
      } else {
        setLogs(prev => [...prev, `⚠ Warning: Step ${currentNode.title} lacks requirement validation.`]);
      }

      setActiveNodeIndex(prev => prev + 1);
    }, 1200);

    return () => clearTimeout(timer);
  }, [isRunning, activeNodeIndex, nodes, insightsMap, setNodes]);

  return (
    <div className="h-full flex flex-col p-6 space-y-6 overflow-hidden">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Process Simulation Environment</h2>
        <div className="flex gap-3">
          {!isRunning ? (
            <button 
              onClick={startSim}
              className="px-6 py-2 bg-green-600 text-white rounded-lg font-medium hover:bg-green-700 shadow-md flex items-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /></svg>
              Start Simulation
            </button>
          ) : (
            <button 
              onClick={stopSim}
              className="px-6 py-2 bg-red-600 text-white rounded-lg font-medium hover:bg-red-700 shadow-md flex items-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1H10a1 1 0 01-1-1v-4z" /></svg>
              Stop & Reset
            </button>
          )}
        </div>
      </div>

      <div className="flex-1 grid grid-cols-3 gap-6 overflow-hidden">
        {/* Visual Map View */}
        <div className="col-span-2 bg-white rounded-2xl border border-slate-200 p-6 relative overflow-auto">
          <div className="flex flex-wrap gap-8 justify-center items-start pt-10">
            {nodes.map(node => (
              <div 
                key={node.id}
                className={`w-48 p-4 rounded-xl border-2 text-center transition-all duration-500 ${node.status === 'success' ? 'bg-green-50 border-green-500 shadow-lg shadow-green-500/20' : node.status === 'failed' ? 'bg-red-50 border-red-500' : node.status === 'running' ? 'bg-blue-50 border-blue-500 animate-pulse' : 'bg-slate-50 border-slate-200'}`}
              >
                <h4 className="font-bold text-sm mb-1">{node.title}</h4>
                <div className="text-[10px] text-slate-500 uppercase tracking-tighter">
                  {node.status === 'success' ? 'VALIDATED' : node.status === 'failed' ? 'UNVALIDATED' : 'WAITING'}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Real-time Logs */}
        <div className="bg-slate-900 rounded-2xl p-6 text-emerald-400 font-mono text-xs overflow-auto">
          <h3 className="text-white font-bold mb-4 uppercase tracking-widest text-xs flex items-center gap-2">
            <span className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>
            System Console
          </h3>
          <div className="space-y-2">
            {logs.map((log, i) => (
              <div key={i} className="flex gap-2">
                <span className="opacity-40">[{new Date().toLocaleTimeString()}]</span>
                <span>{log}</span>
              </div>
            ))}
            {isRunning && <div className="animate-pulse">_</div>}
          </div>
        </div>
      </div>
    </div>
  );
};

