import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ProcessNode, Connection, SlotType } from '../types';

interface EditorProps {
  nodes: ProcessNode[];
  connections: Connection[];
  onAddNode: (x?: number, y?: number, layer?: number) => void;
  onUpdateNode: (id: string, updates: Partial<ProcessNode>) => void;
  onDeleteNode: (id: string) => void;
  onAddConnection: (conn: Connection) => void;
  projectTitle: string;
  setProjectTitle: (val: string) => void;
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
}

const COLORS = [
  { name: 'White', value: '#ffffff' },
  { name: 'Blue', value: '#eff6ff' },
  { name: 'Green', value: '#f0fdf4' },
  { name: 'Amber', value: '#fffbeb' },
  { name: 'Red', value: '#fef2f2' },
  { name: 'Slate', value: '#f8fafc' },
];

const Editor: React.FC<EditorProps> = ({ 
  nodes, connections, onAddNode, onUpdateNode, onDeleteNode, onAddConnection, 
  projectTitle, setProjectTitle, selectedNodeId, setSelectedNodeId 
}) => {
  const [isConnecting, setIsConnecting] = useState<{ nodeId: string, slotId: string } | null>(null);
  const [contextMenu, setContextMenu] = useState<{ x: number, y: number, nodeId: string } | null>(null);
  const [draggingNodeId, setDraggingNodeId] = useState<string | null>(null);
  const dragOffset = useRef({ x: 0, y: 0 });
  const canvasRef = useRef<HTMLDivElement>(null);

  // Close context menu on click elsewhere
  useEffect(() => {
    const closeMenu = () => setContextMenu(null);
    window.addEventListener('click', closeMenu);
    return () => window.removeEventListener('click', closeMenu);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (draggingNodeId && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const x = e.clientX - rect.left - dragOffset.current.x;
      const y = e.clientY - rect.top - dragOffset.current.y;
      const layer = Math.floor(y / 200);
      onUpdateNode(draggingNodeId, { x, y, layer });
    }
  }, [draggingNodeId, onUpdateNode]);

  const handleMouseUp = () => setDraggingNodeId(null);

  const handleNodeMouseDown = (e: React.MouseEvent, nodeId: string) => {
    if (e.button !== 0) return; // Only left click
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      setDraggingNodeId(nodeId);
      setSelectedNodeId(nodeId);
      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      dragOffset.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  const handleNodeContextMenu = (e: React.MouseEvent, nodeId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setContextMenu({ x: e.clientX, y: e.clientY, nodeId });
  };

  const handleSlotClick = (nodeId: string, slotId: string) => {
    if (!isConnecting) {
      setIsConnecting({ nodeId, slotId });
    } else {
      if (isConnecting.nodeId !== nodeId) {
        onAddConnection({
          id: Math.random().toString(36).substr(2, 9),
          sourceNodeId: isConnecting.nodeId,
          sourceSlotId: isConnecting.slotId,
          targetNodeId: nodeId,
          targetSlotId: slotId,
          biDirectional: false
        });
      }
      setIsConnecting(null);
    }
  };

  const addSlot = (nodeId: string, type: SlotType) => {
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      onUpdateNode(nodeId, {
        slots: [...node.slots, { id: Math.random().toString(36).substr(2, 9), label: `New ${type}`, type }]
      });
    }
  };

  const activeContextNode = nodes.find(n => n.id === contextMenu?.nodeId);

  return (
    <div className="flex flex-col h-full select-none" onMouseMove={handleMouseMove} onMouseUp={handleMouseUp}>
      {/* Top Formatting Toolbar */}
      <div className="bg-white border-b border-slate-200 p-2 flex items-center justify-between shadow-sm z-30">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1 border-r pr-4">
            <input 
              type="text" 
              value={projectTitle}
              onChange={(e) => setProjectTitle(e.target.value)}
              className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500 w-64"
            />
          </div>
          <div className="flex items-center gap-2">
            <button className="p-2 hover:bg-slate-100 rounded text-slate-600" title="Text Bold"><b>B</b></button>
            <button className="p-2 hover:bg-slate-100 rounded text-slate-600" title="Text Italic"><i>I</i></button>
            <div className="w-[1px] h-6 bg-slate-200 mx-1"></div>
            <button 
              onClick={() => onAddNode(100, 100 + (nodes.length * 20))}
              className="flex items-center gap-2 px-4 py-1.5 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-500/20"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
              + New Process Step
            </button>
          </div>
        </div>

        <div className="flex items-center gap-3 pr-4">
           <button className="text-xs text-slate-400 font-medium hover:text-slate-600">Export JSON</button>
           <button className="text-xs text-blue-600 font-bold hover:underline">Clear Canvas</button>
        </div>
      </div>

      <div 
        ref={canvasRef}
        className="flex-1 relative bg-slate-100 overflow-auto canvas-grid scroll-smooth"
        style={{
          backgroundImage: 'radial-gradient(circle, #cbd5e1 1px, transparent 1px)',
          backgroundSize: '24px 24px'
        }}
      >
        {/* Horizontal Layers with Labels */}
        {[0, 1, 2, 3, 4, 5, 6, 7].map(i => (
          <div key={i} className="absolute w-full border-b border-slate-300 pointer-events-none" style={{ top: i * 200, height: 200 }}>
            <span className="absolute left-4 top-4 text-[10px] font-black text-slate-300 uppercase tracking-widest">PHASE {i + 1}</span>
            <span className="absolute right-4 top-4 text-xs font-bold text-slate-400 bg-white/80 px-2 py-1 rounded border border-slate-200 shadow-sm">LAYER {i + 1}</span>
          </div>
        ))}

        {/* SVG layer for Connections */}
        <svg className="absolute inset-0 w-full h-full pointer-events-none" style={{ minWidth: 4000, minHeight: 4000 }}>
          <defs>
            <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orientation="auto">
              <polygon points="0 0, 10 3.5, 0 7" fill="#64748b" />
            </marker>
          </defs>
          {connections.map(conn => {
            const source = nodes.find(n => n.id === conn.sourceNodeId);
            const target = nodes.find(n => n.id === conn.targetNodeId);
            if (!source || !target) return null;

            const x1 = source.x + source.width;
            const y1 = source.y + 40 + (source.slots.findIndex(s => s.id === conn.sourceSlotId) * 24);
            const x2 = target.x;
            const y2 = target.y + 40 + (target.slots.findIndex(s => s.id === conn.targetSlotId) * 24);

            return (
              <g key={conn.id}>
                <path 
                  d={`M ${x1} ${y1} C ${x1 + 80} ${y1}, ${x2 - 80} ${y2}, ${x2} ${y2}`}
                  stroke="#64748b"
                  strokeWidth="2.5"
                  fill="none"
                  markerEnd="url(#arrowhead)"
                  className="transition-all duration-300"
                />
              </g>
            );
          })}
        </svg>

        {/* Nodes */}
        {nodes.map(node => (
          <div
            key={node.id}
            onMouseDown={(e) => handleNodeMouseDown(e, node.id)}
            onContextMenu={(e) => handleNodeContextMenu(e, node.id)}
            className={`absolute rounded-xl border-2 shadow-sm transition-shadow group flex flex-col cursor-move select-none ${selectedNodeId === node.id ? 'border-blue-500 ring-4 ring-blue-500/10 z-20' : 'border-slate-300 hover:border-slate-400 z-10'}`}
            style={{ 
              left: node.x, 
              top: node.y, 
              width: node.width,
              minHeight: node.height,
              backgroundColor: node.color || '#ffffff'
            }}
          >
            {/* Header / Title Slot */}
            <div className="bg-white/50 backdrop-blur-sm border-b border-slate-200 px-3 py-2 flex items-center justify-between rounded-t-xl">
              <input 
                className="font-bold text-sm bg-transparent w-full focus:outline-none"
                value={node.title}
                onChange={(e) => onUpdateNode(node.id, { title: e.target.value })}
                onMouseDown={(e) => e.stopPropagation()}
              />
              <div className="flex gap-1">
                 <button 
                  onClick={(e) => { e.stopPropagation(); addSlot(node.id, 'task'); }}
                  className="w-5 h-5 flex items-center justify-center bg-slate-100 hover:bg-slate-200 rounded text-slate-500 transition-colors"
                  title="Add Task Slot"
                >
                  <span className="text-xs">+</span>
                </button>
              </div>
            </div>

            {/* Content / Slots */}
            <div className="p-3 space-y-2">
              <textarea 
                className="text-[11px] text-slate-600 w-full resize-none h-12 border-none bg-transparent focus:outline-none placeholder:italic"
                placeholder="Specify process requirements or steps..."
                value={node.description}
                onChange={(e) => onUpdateNode(node.id, { description: e.target.value })}
                onMouseDown={(e) => e.stopPropagation()}
              />
              <div className="space-y-1">
                {node.slots.map(slot => (
                  <div 
                    key={slot.id} 
                    className="flex items-center justify-between text-[11px] group/slot"
                    onMouseDown={(e) => e.stopPropagation()}
                  >
                    <div className="flex items-center gap-2">
                      <div className={`w-2 h-2 rounded-full ${slot.type === 'task' ? 'bg-blue-400' : slot.type === 'decision' ? 'bg-amber-400' : 'bg-emerald-400'}`}></div>
                      <input 
                        className="bg-transparent hover:bg-white/60 focus:bg-white rounded px-1 transition-all outline-none"
                        value={slot.label}
                        onChange={(e) => {
                          const newSlots = node.slots.map(s => s.id === slot.id ? { ...s, label: e.target.value } : s);
                          onUpdateNode(node.id, { slots: newSlots });
                        }}
                      />
                    </div>
                    <button 
                      onClick={() => handleSlotClick(node.id, slot.id)}
                      className={`w-4 h-4 rounded-full border border-slate-300 flex items-center justify-center transition-all ${isConnecting?.slotId === slot.id ? 'bg-blue-500 border-blue-500 text-white scale-125' : 'bg-white hover:bg-blue-50'}`}
                    >
                      <div className={`w-1.5 h-1.5 rounded-full ${isConnecting?.slotId === slot.id ? 'bg-white' : 'bg-slate-300'}`}></div>
                    </button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ))}

        {/* Custom Context Menu (Toolbar) */}
        {contextMenu && activeContextNode && (
          <div 
            className="fixed z-50 bg-white border border-slate-200 shadow-2xl rounded-xl p-4 w-64 space-y-4"
            style={{ left: contextMenu.x, top: contextMenu.y }}
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex justify-between items-center mb-2">
              <span className="text-xs font-black text-slate-400 uppercase tracking-tighter">Step Settings</span>
              <button onClick={() => setContextMenu(null)} className="text-slate-300 hover:text-slate-600">×</button>
            </div>

            {/* Size Controls */}
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-500 uppercase">Dimensions</label>
              <div className="grid grid-cols-2 gap-2">
                <div className="flex flex-col">
                  <span className="text-[9px] text-slate-400">Width</span>
                  <input 
                    type="number" 
                    className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-xs"
                    value={activeContextNode.width}
                    onChange={(e) => onUpdateNode(activeContextNode.id, { width: parseInt(e.target.value) || 200 })}
                  />
                </div>
                <div className="flex flex-col">
                  <span className="text-[9px] text-slate-400">Height</span>
                  <input 
                    type="number" 
                    className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-xs"
                    value={activeContextNode.height}
                    onChange={(e) => onUpdateNode(activeContextNode.id, { height: parseInt(e.target.value) || 100 })}
                  />
                </div>
              </div>
            </div>

            {/* Color Selection */}
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-slate-500 uppercase">Style Color</label>
              <div className="flex flex-wrap gap-2">
                {COLORS.map(c => (
                  <button
                    key={c.value}
                    onClick={() => onUpdateNode(activeContextNode.id, { color: c.value })}
                    className={`w-6 h-6 rounded-full border transition-transform hover:scale-110 ${activeContextNode.color === c.value ? 'border-blue-500 ring-2 ring-blue-200' : 'border-slate-200'}`}
                    style={{ backgroundColor: c.value }}
                    title={c.name}
                  />
                ))}
              </div>
            </div>

            <div className="pt-2 border-t border-slate-100 flex gap-2">
               <button 
                onClick={() => { onDeleteNode(activeContextNode.id); setContextMenu(null); }}
                className="flex-1 bg-red-50 hover:bg-red-100 text-red-600 text-xs py-2 rounded-lg font-bold transition-colors flex items-center justify-center gap-2"
              >
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                Delete Box
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Node Control Legend */}
      <div className="p-3 bg-white border-t flex justify-between items-center text-xs text-slate-500">
        <div className="flex gap-4">
          <div className="flex items-center gap-1"><div className="w-2 h-2 bg-blue-400 rounded-full"></div> Tasks</div>
          <div className="flex items-center gap-1"><div className="w-2 h-2 bg-amber-400 rounded-full"></div> Decisions</div>
          <div className="flex items-center gap-1"><div className="w-2 h-2 bg-emerald-400 rounded-full"></div> Operations</div>
        </div>
        <p className="font-medium italic">Drag to move • Right-click to edit box properties • Click dots to connect</p>
      </div>
    </div>
  );
};

export default Editor;

export type SlotType = 'task' | 'decision' | 'operation';
export type ConnectionType = 'dependency' | 'data-flow' | 'resource-flow' | 'informational';

export interface ProcessSlot {
  id: string;
  label: string;
  type: SlotType;
}

export interface ProcessNode {
  id: string;
  title: string;
  description: string;
  x: number;
  y: number;
  width: number;
  height: number;
  color: string;
  slots: ProcessSlot[];
  layer: number; // For horizontal positioning
  status: 'idle' | 'running' | 'success' | 'failed';
}

export interface Connection {
  id: string;
  sourceNodeId: string;
  sourceSlotId: string;
  targetNodeId: string;
  targetSlotId: string;
  biDirectional: boolean;
  type: ConnectionType;
  label?: string;
}

export interface Resource {
  id: string;
  name: string;
  type: string;
  cost: number;
  available: boolean;
}

export interface NodeInsights {
  nodeId: string;
  requirements: string[];
  resources: Resource[];
  summary: string;
  executionStyle: string;
}

export type PageView = 'editor' | 'insights' | 'report' | 'simulation';

import React, { useState, useCallback } from 'react';
import { PageView, ProcessNode, Connection, NodeInsights } from './types';
import Sidebar from './components/Sidebar';
import Editor from './components/Editor';
import Insights from './components/Insights';
import Report from './components/Report';
import Simulation from './components/Simulation';

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageView>('editor');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [projectTitle, setProjectTitle] = useState('New Process Master Plan');

  const [nodes, setNodes] = useState<ProcessNode[]>([]);
  const [connections, setConnections] = useState<Connection[]>([]);
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [insightsMap, setInsightsMap] = useState<Record<string, NodeInsights>>({});

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const addNode = useCallback((x: number = 100, y: number = 100, layer: number = 0) => {
    const newNode: ProcessNode = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Step',
      description: 'Step Description',
      x,
      y,
      width: 220,
      height: 120,
      color: '#ffffff',
      slots: [
        { id: Math.random().toString(36).substr(2, 9), label: 'Primary Task', type: 'task' }
      ],
      layer,
      status: 'idle'
    };
    setNodes(prev => [...prev, newNode]);
  }, []);

  const updateNode = useCallback((id: string, updates: Partial<ProcessNode>) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, ...updates } : n));
  }, []);

  const deleteNode = useCallback((id: string) => {
    setNodes(prev => prev.filter(n => n.id !== id));
    setConnections(prev => prev.filter(c => c.sourceNodeId !== id && c.targetNodeId !== id));
    if (selectedNodeId === id) setSelectedNodeId(null);
  }, [selectedNodeId]);

  const addConnection = useCallback((conn: Connection) => {
    setConnections(prev => [...prev, conn]);
  }, []);

  const updateConnection = useCallback((id: string, updates: Partial<Connection>) => {
    setConnections(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  }, []);

  const deleteConnection = useCallback((id: string) => {
    setConnections(prev => prev.filter(c => c.id !== id));
  }, []);

  const renderPage = () => {
    switch (activePage) {
      case 'editor':
        return (
          <Editor 
            nodes={nodes} 
            connections={connections} 
            onAddNode={addNode} 
            onUpdateNode={updateNode} 
            onDeleteNode={deleteNode}
            onAddConnection={addConnection}
            onUpdateConnection={updateConnection}
            onDeleteConnection={deleteConnection}
            projectTitle={projectTitle}
            setProjectTitle={setProjectTitle}
            selectedNodeId={selectedNodeId}
            setSelectedNodeId={setSelectedNodeId}
          />
        );
      case 'insights':
        return (
          <Insights 
            nodes={nodes}
            selectedNodeId={selectedNodeId}
            insightsMap={insightsMap}
            setInsightsMap={setInsightsMap}
          />
        );
      case 'simulation':
        return (
          <Simulation 
            nodes={nodes} 
            connections={connections}
            insightsMap={insightsMap}
            setNodes={setNodes}
          />
        );
      case 'report':
        return (
          <Report 
            nodes={nodes} 
            connections={connections} 
            insightsMap={insightsMap}
            projectTitle={projectTitle}
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 text-slate-900 overflow-hidden">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={toggleSidebar} 
        activePage={activePage} 
        setActivePage={setActivePage} 
      />

      <main className="flex-1 flex flex-col transition-all duration-300">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-30">
          <div className="flex items-center gap-4">
            <button 
              onClick={toggleSidebar}
              className="p-2 hover:bg-slate-100 rounded-lg transition-colors"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
              {projectTitle}
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="px-3 py-1 bg-blue-50 text-blue-600 rounded-full text-xs font-semibold">
              v1.0.6 Design
            </div>
            <div className="w-10 h-10 rounded-full bg-slate-200 overflow-hidden border border-white shadow-sm">
              <img src="https://picsum.photos/40/40" alt="Avatar" />
            </div>
          </div>
        </header>

        <div className="flex-1 relative overflow-hidden bg-slate-100">
          {renderPage()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ProcessNode, Connection, SlotType, ConnectionType } from '../types';

interface EditorProps {
  nodes: ProcessNode[];
  connections: Connection[];
  onAddNode: (x?: number, y?: number, layer?: number) => void;
  onUpdateNode: (id: string, updates: Partial<ProcessNode>) => void;
  onDeleteNode: (id: string) => void;
  onAddConnection: (conn: Connection) => void;
  onUpdateConnection: (id: string, updates: Partial<Connection>) => void;
  onDeleteConnection: (id: string) => void;
  projectTitle: string;
  setProjectTitle: (val: string) => void;
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
}

const COLORS = [
  { name: 'White', value: '#ffffff' },
  { name: 'Blue', value: '#eff6ff' },
  { name: 'Green', value: '#f0fdf4' },
  { name: 'Amber', value: '#fffbeb' },
  { name: 'Red', value: '#fef2f2' },
  { name: 'Slate', value: '#f8fafc' },
];

const CONNECTION_TYPES: { label: string, value: ConnectionType, color: string }[] = [
  { label: 'Dependency', value: 'dependency', color: '#64748b' },
  { label: 'Data Flow', value: 'data-flow', color: '#3b82f6' },
  { label: 'Resource Flow', value: 'resource-flow', color: '#10b981' },
  { label: 'Informational', value: 'informational', color: '#f59e0b' },
];

const Editor: React.FC<EditorProps> = ({ 
  nodes, connections, onAddNode, onUpdateNode, onDeleteNode, onAddConnection, 
  onUpdateConnection, onDeleteConnection,
  projectTitle, setProjectTitle, selectedNodeId, setSelectedNodeId 
}) => {
  const [isConnecting, setIsConnecting] = useState<{ nodeId: string, slotId: string } | null>(null);
  const [nodeContextMenu, setNodeContextMenu] = useState<{ x: number, y: number, nodeId: string } | null>(null);
  const [lineContextMenu, setLineContextMenu] = useState<{ x: number, y: number, connId: string } | null>(null);
  const [draggingNodeId, setDraggingNodeId] = useState<string | null>(null);
  const dragOffset = useRef({ x: 0, y: 0 });
  const canvasRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const closeMenus = () => {
      setNodeContextMenu(null);
      setLineContextMenu(null);
    };
    window.addEventListener('click', closeMenus);
    return () => window.removeEventListener('click', closeMenus);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (draggingNodeId && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const scrollX = canvasRef.current.scrollLeft;
      const scrollY = canvasRef.current.scrollTop;
      const x = e.clientX - rect.left + scrollX - dragOffset.current.x;
      const y = e.clientY - rect.top + scrollY - dragOffset.current.y;
      const layer = Math.floor(y / 200);
      onUpdateNode(draggingNodeId, { x, y, layer });
    }
  }, [draggingNodeId, onUpdateNode]);

  const handleMouseUp = () => setDraggingNodeId(null);

  const handleNodeMouseDown = (e: React.MouseEvent, nodeId: string) => {
    if (e.button !== 0) return; 
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      setDraggingNodeId(nodeId);
      setSelectedNodeId(nodeId);
      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      dragOffset.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  const handleNodeContextMenu = (e: React.MouseEvent, nodeId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setLineContextMenu(null);
    setNodeContextMenu({ x: e.clientX, y: e.clientY, nodeId });
  };

  const handleLineContextMenu = (e: React.MouseEvent, connId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setNodeContextMenu(null);
    setLineContextMenu({ x: e.clientX, y: e.clientY, connId });
  };

  const handleSlotClick = (e: React.MouseEvent, nodeId: string, slotId: string) => {
    e.stopPropagation();
    if (!isConnecting) {
      setIsConnecting({ nodeId, slotId });
    } else {
      if (isConnecting.nodeId !== nodeId) {
        onAddConnection({
          id: Math.random().toString(36).substr(2, 9),
          sourceNodeId: isConnecting.nodeId,
          sourceSlotId: isConnecting.slotId,
          targetNodeId: nodeId,
          targetSlotId: slotId,
          biDirectional: false,
          type: 'dependency'
        });
      }
      setIsConnecting(null);
    }
  };

  const addSlot = (nodeId: string, type: SlotType) => {
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      onUpdateNode(nodeId, {
        slots: [...node.slots, { id: Math.random().toString(36).substr(2, 9), label: `New ${type}`, type }]
      });
    }
  };

  const activeContextNode = nodes.find(n => n.id === nodeContextMenu?.nodeId);
  const activeContextConn = connections.find(c => c.id === lineContextMenu?.connId);

  return (
    <div className="flex flex-col h-full select-none" onMouseMove={handleMouseMove} onMouseUp={handleMouseUp}>
      <div className="bg-white border-b border-slate-200 p-2 flex items-center justify-between shadow-sm z-30">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1 border-r pr-4">
            <input 
              type="text" 
              value={projectTitle}
              onChange={(e) => setProjectTitle(e.target.value)}
              className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500 w-64"
            />
          </div>
          <div className="flex items-center gap-2">
            <button className="px-3 py-1 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-all flex items-center gap-2 shadow-lg shadow-blue-500/10" onClick={() => onAddNode(200, 100 + (nodes.length * 40))}>
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
              New Process Step
            </button>
            <div className="w-[1px] h-6 bg-slate-200 mx-1"></div>
            <button className="p-2 hover:bg-slate-100 rounded text-slate-600" title="Text Bold"><b>B</b></button>
            <button className="p-2 hover:bg-slate-100 rounded text-slate-600" title="Text Italic"><i>I</i></button>
          </div>
        </div>
        <div className="flex items-center gap-3 pr-4">
           <button className="text-xs text-slate-400 font-medium hover:text-slate-600">Export Blueprint</button>
        </div>
      </div>

      <div 
        ref={canvasRef}
        className="flex-1 relative bg-slate-100 overflow-auto canvas-grid"
        style={{
          backgroundImage: 'radial-gradient(circle, #cbd5e1 1px, transparent 1px)',
          backgroundSize: '24px 24px'
        }}
      >
        <div style={{ minWidth: 4000, minHeight: 4000, position: 'relative' }}>
          {[0, 1, 2, 3, 4, 5, 6, 7].map(i => (
            <div key={i} className="absolute w-full border-b border-slate-300 pointer-events-none" style={{ top: i * 200, height: 200 }}>
              <span className="absolute left-4 top-4 text-[10px] font-black text-slate-300 uppercase tracking-widest">PROCESS PHASE {i + 1}</span>
            </div>
          ))}

          <svg className="absolute inset-0 w-full h-full pointer-events-none">
            <defs>
              {CONNECTION_TYPES.map(ct => (
                <marker key={ct.value} id={`arrow-${ct.value}`} markerWidth="10" markerHeight="7" refX="9" refY="3.5" orientation="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill={ct.color} />
                </marker>
              ))}
            </defs>
            {connections.map(conn => {
              const srcNode = nodes.find(n => n.id === conn.sourceNodeId);
              const trgNode = nodes.find(n => n.id === conn.targetNodeId);
              if (!srcNode || !trgNode) return null;

              const srcSlotIdx = srcNode.slots.findIndex(s => s.id === conn.sourceSlotId);
              const trgSlotIdx = trgNode.slots.findIndex(s => s.id === conn.targetSlotId);

              // Position relative to slots
              const x1 = srcNode.x + srcNode.width - 12;
              const y1 = srcNode.y + 70 + (srcSlotIdx * 20);
              const x2 = trgNode.x + 12;
              const y2 = trgNode.y + 70 + (trgSlotIdx * 20);

              const connType = CONNECTION_TYPES.find(ct => ct.value === conn.type) || CONNECTION_TYPES[0];

              return (
                <g key={conn.id}>
                  <path 
                    d={`M ${x1} ${y1} C ${x1 + 60} ${y1}, ${x2 - 60} ${y2}, ${x2} ${y2}`}
                    stroke={connType.color}
                    strokeWidth="3"
                    fill="none"
                    markerEnd={`url(#arrow-${connType.value})`}
                    className="pointer-events-auto cursor-pointer hover:stroke-blue-400 transition-colors"
                    onContextMenu={(e) => handleLineContextMenu(e, conn.id)}
                  />
                  <text x={(x1+x2)/2} y={(y1+y2)/2 - 10} className="text-[10px] fill-slate-400 font-bold select-none text-center">
                    {conn.label || ''}
                  </text>
                </g>
              );
            })}
          </svg>

          {nodes.map(node => (
            <div
              key={node.id}
              onMouseDown={(e) => handleNodeMouseDown(e, node.id)}
              onContextMenu={(e) => handleNodeContextMenu(e, node.id)}
              className={`absolute rounded-xl border-2 shadow-sm flex flex-col cursor-move transition-shadow select-none ${selectedNodeId === node.id ? 'border-blue-500 ring-4 ring-blue-500/10 z-20' : 'border-slate-300 hover:border-slate-400 z-10'}`}
              style={{ 
                left: node.x, 
                top: node.y, 
                width: node.width,
                minHeight: node.height,
                backgroundColor: node.color || '#ffffff'
              }}
            >
              <div className="bg-white/50 backdrop-blur-sm border-b border-slate-200 px-3 py-2 flex items-center justify-between rounded-t-xl">
                <input 
                  className="font-bold text-sm bg-transparent w-full focus:outline-none"
                  value={node.title}
                  onChange={(e) => onUpdateNode(node.id, { title: e.target.value })}
                  onMouseDown={(e) => e.stopPropagation()}
                />
                <button 
                  onClick={(e) => { e.stopPropagation(); addSlot(node.id, 'task'); }}
                  className="w-5 h-5 flex items-center justify-center bg-slate-100 hover:bg-slate-200 rounded text-slate-500"
                >
                  <span className="text-xs">+</span>
                </button>
              </div>

              <div className="p-3 space-y-2">
                <textarea 
                  className="text-[11px] text-slate-600 w-full resize-none h-12 border-none bg-transparent focus:outline-none placeholder:italic"
                  placeholder="Step requirements..."
                  value={node.description}
                  onChange={(e) => onUpdateNode(node.id, { description: e.target.value })}
                  onMouseDown={(e) => e.stopPropagation()}
                />
                <div className="space-y-1">
                  {node.slots.map(slot => (
                    <div 
                      key={slot.id} 
                      className="flex items-center justify-between text-[11px] h-5"
                      onMouseDown={(e) => e.stopPropagation()}
                    >
                      <div className="flex items-center gap-2 overflow-hidden flex-1">
                        <div className={`w-2 h-2 rounded-full flex-shrink-0 ${slot.type === 'task' ? 'bg-blue-400' : slot.type === 'decision' ? 'bg-amber-400' : 'bg-emerald-400'}`}></div>
                        <input 
                          className="bg-transparent hover:bg-white/60 focus:bg-white rounded px-1 outline-none w-full truncate"
                          value={slot.label}
                          onChange={(e) => {
                            const newSlots = node.slots.map(s => s.id === slot.id ? { ...s, label: e.target.value } : s);
                            onUpdateNode(node.id, { slots: newSlots });
                          }}
                        />
                      </div>
                      <button 
                        onClick={(e) => handleSlotClick(e, node.id, slot.id)}
                        className={`w-4 h-4 rounded-full border border-slate-300 flex items-center justify-center transition-all ${isConnecting?.slotId === slot.id ? 'bg-blue-500 border-blue-500 scale-125' : 'bg-white hover:bg-blue-50'}`}
                      >
                        <div className={`w-1.5 h-1.5 rounded-full ${isConnecting?.slotId === slot.id ? 'bg-white' : 'bg-slate-300'}`}></div>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Node Context Menu */}
        {nodeContextMenu && activeContextNode && (
          <div className="fixed z-50 bg-white border border-slate-200 shadow-2xl rounded-xl p-4 w-64 space-y-4" style={{ left: nodeContextMenu.x, top: nodeContextMenu.y }} onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center"><span className="text-xs font-black text-slate-400 uppercase">Edit Box</span><button onClick={() => setNodeContextMenu(null)}>×</button></div>
            <div className="grid grid-cols-2 gap-2">
              <div className="flex flex-col"><span className="text-[9px] text-slate-400">Width</span><input type="number" className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-xs" value={activeContextNode.width} onChange={(e) => onUpdateNode(activeContextNode.id, { width: parseInt(e.target.value) || 200 })} /></div>
              <div className="flex flex-col"><span className="text-[9px] text-slate-400">Height</span><input type="number" className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-xs" value={activeContextNode.height} onChange={(e) => onUpdateNode(activeContextNode.id, { height: parseInt(e.target.value) || 100 })} /></div>
            </div>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => <button key={c.value} onClick={() => onUpdateNode(activeContextNode.id, { color: c.value })} className={`w-6 h-6 rounded-full border ${activeContextNode.color === c.value ? 'ring-2 ring-blue-500' : ''}`} style={{ backgroundColor: c.value }} />)}
            </div>
            <button onClick={() => { onDeleteNode(activeContextNode.id); setNodeContextMenu(null); }} className="w-full bg-red-50 text-red-600 text-xs py-2 rounded-lg font-bold hover:bg-red-100">Delete Step</button>
          </div>
        )}

        {/* Line Context Menu */}
        {lineContextMenu && activeContextConn && (
          <div className="fixed z-50 bg-white border border-slate-200 shadow-2xl rounded-xl p-4 w-56 space-y-3" style={{ left: lineContextMenu.x, top: lineContextMenu.y }} onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center text-xs font-black text-slate-400 uppercase tracking-tighter">Connection Settings</div>
            <div className="space-y-1">
              {CONNECTION_TYPES.map(ct => (
                <button 
                  key={ct.value}
                  onClick={() => { onUpdateConnection(activeContextConn.id, { type: ct.value }); setLineContextMenu(null); }}
                  className={`w-full text-left px-3 py-2 text-xs rounded-lg flex items-center gap-2 hover:bg-slate-50 ${activeContextConn.type === ct.value ? 'bg-blue-50 text-blue-700 font-bold' : 'text-slate-600'}`}
                >
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: ct.color }}></div>
                  {ct.label}
                </button>
              ))}
            </div>
            <div className="border-t pt-2 mt-2">
              <button onClick={() => { onDeleteConnection(activeContextConn.id); setLineContextMenu(null); }} className="w-full bg-slate-50 text-slate-600 text-[11px] py-2 rounded-lg font-bold hover:bg-red-50 hover:text-red-600 transition-colors">Remove Relationship</button>
            </div>
          </div>
        )}
      </div>

      <div className="p-3 bg-white border-t flex justify-between items-center text-xs text-slate-500 z-10">
        <div className="flex gap-4">
          {CONNECTION_TYPES.map(ct => (
            <div key={ct.value} className="flex items-center gap-1">
              <div className="w-3 h-[2px]" style={{ backgroundColor: ct.color }}></div> {ct.label}
            </div>
          ))}
        </div>
        <p className="font-medium italic">Use the top menu to add steps • Drag steps to organize • Right-click lines/boxes to configure</p>
      </div>
    </div>
  );
};

export default Editor;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ProcessNode, Connection, SlotType, ConnectionType } from '../types';

interface EditorProps {
  nodes: ProcessNode[];
  connections: Connection[];
  onAddNode: (x?: number, y?: number, layer?: number) => void;
  onUpdateNode: (id: string, updates: Partial<ProcessNode>) => void;
  onDeleteNode: (id: string) => void;
  onAddConnection: (conn: Connection) => void;
  onUpdateConnection: (id: string, updates: Partial<Connection>) => void;
  onDeleteConnection: (id: string) => void;
  projectTitle: string;
  setProjectTitle: (val: string) => void;
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
}

const COLORS = [
  { name: 'White', value: '#ffffff' },
  { name: 'Blue', value: '#eff6ff' },
  { name: 'Green', value: '#f0fdf4' },
  { name: 'Amber', value: '#fffbeb' },
  { name: 'Red', value: '#fef2f2' },
  { name: 'Slate', value: '#f8fafc' },
];

const CONNECTION_TYPES: { label: string, value: ConnectionType, color: string, dash?: string }[] = [
  { label: 'Dependency', value: 'dependency', color: '#64748b' },
  { label: 'Data Flow', value: 'data-flow', color: '#3b82f6' },
  { label: 'Resource Flow', value: 'resource-flow', color: '#10b981', dash: '5,5' },
  { label: 'Informational', value: 'informational', color: '#f59e0b', dash: '2,2' },
];

const Editor: React.FC<EditorProps> = ({ 
  nodes, connections, onAddNode, onUpdateNode, onDeleteNode, onAddConnection, 
  onUpdateConnection, onDeleteConnection,
  projectTitle, setProjectTitle, selectedNodeId, setSelectedNodeId 
}) => {
  const [isConnecting, setIsConnecting] = useState<{ nodeId: string, slotId: string } | null>(null);
  const [nodeContextMenu, setNodeContextMenu] = useState<{ x: number, y: number, nodeId: string } | null>(null);
  const [lineContextMenu, setLineContextMenu] = useState<{ x: number, y: number, connId: string } | null>(null);
  const [draggingNodeId, setDraggingNodeId] = useState<string | null>(null);
  const dragOffset = useRef({ x: 0, y: 0 });
  const canvasRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const closeMenus = () => {
      setNodeContextMenu(null);
      setLineContextMenu(null);
    };
    window.addEventListener('click', closeMenus);
    return () => window.removeEventListener('click', closeMenus);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (draggingNodeId && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const scrollX = canvasRef.current.scrollLeft;
      const scrollY = canvasRef.current.scrollTop;
      const x = e.clientX - rect.left + scrollX - dragOffset.current.x;
      const y = e.clientY - rect.top + scrollY - dragOffset.current.y;
      const layer = Math.floor(y / 200);
      onUpdateNode(draggingNodeId, { x, y, layer });
    }
  }, [draggingNodeId, onUpdateNode]);

  const handleMouseUp = () => setDraggingNodeId(null);

  const handleNodeMouseDown = (e: React.MouseEvent, nodeId: string) => {
    if (e.button !== 0) return; 
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      setDraggingNodeId(nodeId);
      setSelectedNodeId(nodeId);
      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      dragOffset.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  const handleNodeContextMenu = (e: React.MouseEvent, nodeId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setLineContextMenu(null);
    setNodeContextMenu({ x: e.clientX, y: e.clientY, nodeId });
  };

  const handleLineContextMenu = (e: React.MouseEvent, connId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setNodeContextMenu(null);
    setLineContextMenu({ x: e.clientX, y: e.clientY, connId });
  };

  // --- RELATIONSHIP CREATION LOGIC ---
  const handleSlotClick = (e: React.MouseEvent, nodeId: string, slotId: string) => {
    e.stopPropagation();
    if (!isConnecting) {
      // Step 1: Start tracking from source slot
      setIsConnecting({ nodeId, slotId });
    } else {
      // Step 2: Complete tracking to target slot
      if (isConnecting.nodeId !== nodeId) {
        onAddConnection({
          id: Math.random().toString(36).substr(2, 9),
          sourceNodeId: isConnecting.nodeId,
          sourceSlotId: isConnecting.slotId,
          targetNodeId: nodeId,
          targetSlotId: slotId,
          biDirectional: false,
          type: 'dependency'
        });
      }
      setIsConnecting(null);
    }
  };

  const addSlot = (nodeId: string, type: SlotType) => {
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      onUpdateNode(nodeId, {
        slots: [...node.slots, { id: Math.random().toString(36).substr(2, 9), label: `New ${type}`, type }]
      });
    }
  };

  const activeContextNode = nodes.find(n => n.id === nodeContextMenu?.nodeId);
  const activeContextConn = connections.find(c => c.id === lineContextMenu?.connId);

  return (
    <div className="flex flex-col h-full select-none" onMouseMove={handleMouseMove} onMouseUp={handleMouseUp}>
      <div className="bg-white border-b border-slate-200 p-2 flex items-center justify-between shadow-sm z-30">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1 border-r pr-4">
            <input 
              type="text" 
              value={projectTitle}
              onChange={(e) => setProjectTitle(e.target.value)}
              className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500 w-64"
            />
          </div>
          <div className="flex items-center gap-2">
            <button className="px-3 py-1 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-all flex items-center gap-2 shadow-lg shadow-blue-500/10" onClick={() => onAddNode(200, 100 + (nodes.length * 40))}>
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
              New Process Step
            </button>
            <div className="w-[1px] h-6 bg-slate-200 mx-1"></div>
            <button className="p-2 hover:bg-slate-100 rounded text-slate-600 font-bold">B</button>
            <button className="p-2 hover:bg-slate-100 rounded text-slate-600 italic">I</button>
          </div>
        </div>
        <div className="flex items-center gap-3 pr-4">
           <button className="text-xs text-slate-400 font-medium hover:text-slate-600">Export Blueprint</button>
        </div>
      </div>

      <div 
        ref={canvasRef}
        className="flex-1 relative bg-slate-100 overflow-auto canvas-grid"
        style={{
          backgroundImage: 'radial-gradient(circle, #cbd5e1 1px, transparent 1px)',
          backgroundSize: '24px 24px'
        }}
      >
        <div style={{ minWidth: 4000, minHeight: 4000, position: 'relative' }}>
          {[0, 1, 2, 3, 4, 5, 6, 7].map(i => (
            <div key={i} className="absolute w-full border-b border-slate-300 pointer-events-none" style={{ top: i * 200, height: 200 }}>
              <span className="absolute left-4 top-4 text-[10px] font-black text-slate-300 uppercase tracking-widest">PROCESS PHASE {i + 1}</span>
            </div>
          ))}

          {/* --- SVG RELATIONSHIP LAYER --- */}
          <svg className="absolute inset-0 w-full h-full pointer-events-none">
            <defs>
              {CONNECTION_TYPES.map(ct => (
                <marker key={ct.value} id={`arrow-${ct.value}`} markerWidth="10" markerHeight="7" refX="9" refY="3.5" orientation="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill={ct.color} />
                </marker>
              ))}
            </defs>
            {connections.map(conn => {
              const srcNode = nodes.find(n => n.id === conn.sourceNodeId);
              const trgNode = nodes.find(n => n.id === conn.targetNodeId);
              if (!srcNode || !trgNode) return null;

              const srcSlotIdx = srcNode.slots.findIndex(s => s.id === conn.sourceSlotId);
              const trgSlotIdx = trgNode.slots.findIndex(s => s.id === conn.targetSlotId);

              // GRAPHICAL POSITIONING: Calculate exact slot midpoints
              // Base Y includes header (37px) + Padding (12px) + slot center offset (10px)
              const x1 = srcNode.x + srcNode.width - 12;
              const y1 = srcNode.y + 37 + 12 + (srcSlotIdx * 20) + 10;
              const x2 = trgNode.x + 12;
              const y2 = trgNode.y + 37 + 12 + (trgSlotIdx * 20) + 10;

              const connType = CONNECTION_TYPES.find(ct => ct.value === conn.type) || CONNECTION_TYPES[0];

              return (
                <g key={conn.id}>
                  <path 
                    d={`M ${x1} ${y1} C ${x1 + 60} ${y1}, ${x2 - 60} ${y2}, ${x2} ${y2}`}
                    stroke={connType.color}
                    strokeWidth="3"
                    strokeDasharray={connType.dash || '0'}
                    fill="none"
                    markerEnd={`url(#arrow-${connType.value})`}
                    className="pointer-events-auto cursor-pointer hover:stroke-blue-400 transition-colors"
                    onContextMenu={(e) => handleLineContextMenu(e, conn.id)}
                  />
                </g>
              );
            })}
          </svg>

          {nodes.map(node => (
            <div
              key={node.id}
              onMouseDown={(e) => handleNodeMouseDown(e, node.id)}
              onContextMenu={(e) => handleNodeContextMenu(e, node.id)}
              className={`absolute rounded-xl border-2 shadow-sm flex flex-col cursor-move transition-shadow select-none ${selectedNodeId === node.id ? 'border-blue-500 ring-4 ring-blue-500/10 z-20' : 'border-slate-300 hover:border-slate-400 z-10'}`}
              style={{ 
                left: node.x, 
                top: node.y, 
                width: node.width,
                minHeight: node.height,
                backgroundColor: node.color || '#ffffff'
              }}
            >
              <div className="bg-white/50 backdrop-blur-sm border-b border-slate-200 px-3 py-2 flex items-center justify-between rounded-t-xl">
                <input 
                  className="font-bold text-sm bg-transparent w-full focus:outline-none"
                  value={node.title}
                  onChange={(e) => onUpdateNode(node.id, { title: e.target.value })}
                  onMouseDown={(e) => e.stopPropagation()}
                />
                <button 
                  onClick={(e) => { e.stopPropagation(); addSlot(node.id, 'task'); }}
                  className="w-5 h-5 flex items-center justify-center bg-slate-100 hover:bg-slate-200 rounded text-slate-500"
                >
                  <span className="text-xs">+</span>
                </button>
              </div>

              <div className="p-3 space-y-2">
                <textarea 
                  className="text-[11px] text-slate-600 w-full resize-none h-12 border-none bg-transparent focus:outline-none placeholder:italic"
                  placeholder="Describe step purpose..."
                  value={node.description}
                  onChange={(e) => onUpdateNode(node.id, { description: e.target.value })}
                  onMouseDown={(e) => e.stopPropagation()}
                />
                <div className="space-y-1">
                  {node.slots.map(slot => (
                    <div 
                      key={slot.id} 
                      className="flex items-center justify-between text-[11px] h-5"
                      onMouseDown={(e) => e.stopPropagation()}
                    >
                      <div className="flex items-center gap-2 overflow-hidden flex-1">
                        <div className={`w-2 h-2 rounded-full flex-shrink-0 ${slot.type === 'task' ? 'bg-blue-400' : slot.type === 'decision' ? 'bg-amber-400' : 'bg-emerald-400'}`}></div>
                        <input 
                          className="bg-transparent hover:bg-white/60 focus:bg-white rounded px-1 outline-none w-full truncate"
                          value={slot.label}
                          onChange={(e) => {
                            const newSlots = node.slots.map(s => s.id === slot.id ? { ...s, label: e.target.value } : s);
                            onUpdateNode(node.id, { slots: newSlots });
                          }}
                        />
                      </div>
                      {/* --- RELATIONSHIP SLOT UI --- */}
                      <button 
                        onClick={(e) => handleSlotClick(e, node.id, slot.id)}
                        className={`w-4 h-4 rounded-full border border-slate-300 flex items-center justify-center transition-all ${isConnecting?.slotId === slot.id ? 'bg-blue-500 border-blue-500 scale-150 shadow-lg' : 'bg-white hover:bg-blue-50 hover:scale-110'}`}
                      >
                        <div className={`w-1.5 h-1.5 rounded-full ${isConnecting?.slotId === slot.id ? 'bg-white' : 'bg-slate-300'}`}></div>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Node Context Menu */}
        {nodeContextMenu && activeContextNode && (
          <div className="fixed z-50 bg-white border border-slate-200 shadow-2xl rounded-xl p-4 w-64 space-y-4" style={{ left: nodeContextMenu.x, top: nodeContextMenu.y }} onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center"><span className="text-xs font-black text-slate-400 uppercase">Edit Box</span><button onClick={() => setNodeContextMenu(null)}>×</button></div>
            <div className="grid grid-cols-2 gap-2">
              <div className="flex flex-col"><span className="text-[9px] text-slate-400 uppercase font-bold">Width</span><input type="number" className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-xs" value={activeContextNode.width} onChange={(e) => onUpdateNode(activeContextNode.id, { width: parseInt(e.target.value) || 200 })} /></div>
              <div className="flex flex-col"><span className="text-[9px] text-slate-400 uppercase font-bold">Height</span><input type="number" className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-xs" value={activeContextNode.height} onChange={(e) => onUpdateNode(activeContextNode.id, { height: parseInt(e.target.value) || 100 })} /></div>
            </div>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => <button key={c.value} onClick={() => onUpdateNode(activeContextNode.id, { color: c.value })} className={`w-6 h-6 rounded-full border transition-all ${activeContextNode.color === c.value ? 'ring-2 ring-blue-500 ring-offset-1 scale-110 shadow-md' : 'hover:scale-105'}`} style={{ backgroundColor: c.value }} />)}
            </div>
            <button onClick={() => { onDeleteNode(activeContextNode.id); setNodeContextMenu(null); }} className="w-full bg-red-50 text-red-600 text-xs py-2 rounded-lg font-bold hover:bg-red-100 transition-colors">Delete Step</button>
          </div>
        )}

        {/* --- CONNECTION CONTEXT MENU --- */}
        {lineContextMenu && activeContextConn && (
          <div className="fixed z-50 bg-white border border-slate-200 shadow-2xl rounded-xl p-4 w-56 space-y-3" style={{ left: lineContextMenu.x, top: lineContextMenu.y }} onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center text-xs font-black text-slate-400 uppercase tracking-tighter">Connection Type</div>
            <div className="space-y-1">
              {CONNECTION_TYPES.map(ct => (
                <button 
                  key={ct.value}
                  onClick={() => { onUpdateConnection(activeContextConn.id, { type: ct.value }); setLineContextMenu(null); }}
                  className={`w-full text-left px-3 py-2 text-xs rounded-lg flex items-center gap-2 hover:bg-slate-50 transition-colors ${activeContextConn.type === ct.value ? 'bg-blue-50 text-blue-700 font-bold' : 'text-slate-600'}`}
                >
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: ct.color }}></div>
                  {ct.label}
                </button>
              ))}
            </div>
            <div className="border-t pt-2 mt-2">
              <button onClick={() => { onDeleteConnection(activeContextConn.id); setLineContextMenu(null); }} className="w-full bg-slate-50 text-slate-600 text-[11px] py-2 rounded-lg font-bold hover:bg-red-50 hover:text-red-600 transition-colors">Delete Relationship</button>
            </div>
          </div>
        )}
      </div>

      <div className="p-3 bg-white border-t flex justify-between items-center text-xs text-slate-500 z-10">
        <div className="flex gap-4">
          {CONNECTION_TYPES.map(ct => (
            <div key={ct.value} className="flex items-center gap-1">
              <div className="w-3 h-[3px] rounded-full" style={{ backgroundColor: ct.color }}></div> {ct.label}
            </div>
          ))}
        </div>
        <p className="font-medium italic">Click a dot on one task then a dot on another to create a relationship • Right-click lines to edit</p>
      </div>
    </div>
  );
};

