import React, { useState } from 'react';
import { ProcessNode, NodeInsights } from '../types';
import { analyzeProcessData } from '../services/geminiService';

interface InsightsProps {
  nodes: ProcessNode[];
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
  insightsMap: Record<string, NodeInsights>;
  setInsightsMap: React.Dispatch<React.SetStateAction<Record<string, NodeInsights>>>;
}

const Insights: React.FC<InsightsProps> = ({ nodes, selectedNodeId, setSelectedNodeId, insightsMap, setInsightsMap }) => {
  const [inputText, setInputText] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [uploadedFiles, setUploadedFiles] = useState<File[]>([]);

  const currentNode = nodes.find(n => n.id === selectedNodeId);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      setUploadedFiles(prev => [...prev, ...Array.from(e.target.files!)]);
    }
  };

  const handleAnalyze = async () => {
    if (!currentNode) return;
    setIsAnalyzing(true);

    // Combine text from various inputs for Gemini context
    const context = `Node: ${currentNode.title}. Description: ${currentNode.description}. User Input: ${inputText}. Files: ${uploadedFiles.map(f => f.name).join(', ')}`;

    const result = await analyzeProcessData(currentNode.title, context);
    if (result) {
      setInsightsMap(prev => ({
        ...prev,
        [currentNode.id]: {
          nodeId: currentNode.id,
          ...result
        }
      }));
    }
    setIsAnalyzing(false);
  };

  const StepSelector = () => (
    <div className="flex items-center gap-3 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 shadow-sm">
      <label htmlFor="step-select" className="text-xs font-bold text-slate-400 uppercase tracking-tight">Active Step:</label>
      <select 
        id="step-select"
        value={selectedNodeId || ''}
        onChange={(e) => setSelectedNodeId(e.target.value || null)}
        className="bg-transparent text-sm font-bold text-slate-800 focus:outline-none cursor-pointer min-w-[200px]"
      >
        <option value="">-- Select a Step --</option>
        {nodes.map(node => (
          <option key={node.id} value={node.id}>
            {node.title || 'Untitled Step'}
          </option>
        ))}
      </select>
    </div>
  );

  if (!selectedNodeId && nodes.length > 0) {
    return (
      <div className="h-full flex flex-col p-6 space-y-6">
        <div className="flex items-center justify-between border-b pb-4">
           <h2 className="text-2xl font-bold text-slate-800">Process Insights</h2>
           <StepSelector />
        </div>
        <div className="flex-1 flex items-center justify-center text-slate-400 flex-col gap-4 bg-white rounded-2xl border border-dashed border-slate-200">
          <svg className="w-16 h-16 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          <div className="text-center">
            <p className="text-lg font-medium text-slate-600">No Step Active</p>
            <p className="text-sm">Please use the selection box above to choose a process step for analysis.</p>
          </div>
        </div>
      </div>
    );
  }

  if (nodes.length === 0) {
    return (
      <div className="h-full flex items-center justify-center text-slate-400 flex-col gap-4">
        <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-2">
           <svg className="w-10 h-10 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v3m0 0v3m0-3h3m-3 0H6m12 0a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
        </div>
        <p className="text-lg font-bold text-slate-500">Your canvas is empty.</p>
        <p className="text-sm max-w-xs text-center">Go to the Design Editor and add some process steps to start generating insights.</p>
      </div>
    );
  }

  const currentInsights = insightsMap[selectedNodeId!];

  return (
    <div className="h-full flex flex-col p-6 space-y-6 overflow-auto">
      <div className="flex items-center justify-between border-b pb-4 sticky top-0 bg-slate-50/80 backdrop-blur-sm z-10">
        <div className="flex flex-col">
          <h2 className="text-2xl font-bold text-slate-800 tracking-tight">Process Intelligence</h2>
          <p className="text-slate-500 text-xs">Analyzing node: <span className="text-blue-600 font-bold">{currentNode?.title}</span></p>
        </div>

        <div className="flex items-center gap-4">
          <StepSelector />
          <button 
            onClick={handleAnalyze}
            disabled={isAnalyzing}
            className={`px-6 py-2 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 disabled:opacity-50 flex items-center gap-2 transition-all shadow-lg shadow-blue-500/20 active:scale-95`}
          >
            {isAnalyzing ? (
              <>
                <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Processing...
              </>
            ) : 'Analyze with AI'}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 pb-10">
        {/* Left: Data Entry Section */}
        <div className="space-y-4">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
            <h3 className="font-bold flex items-center gap-2 text-slate-800">
              <div className="w-8 h-8 rounded-lg bg-blue-50 flex items-center justify-center">
                <svg className="w-4 h-4 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
              </div>
              Contextual Data Entry
            </h3>

            <textarea 
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="Paste relevant technical documentation, constraints, or specific step details here to help the AI understand the context..."
              className="w-full h-44 p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 focus:outline-none transition-all resize-none"
            />

            <div className="border-2 border-dashed border-slate-200 rounded-xl p-8 text-center hover:bg-blue-50/30 hover:border-blue-200 transition-all cursor-pointer relative group">
              <input 
                type="file" 
                multiple 
                onChange={handleFileUpload}
                className="absolute inset-0 opacity-0 cursor-pointer"
              />
              <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-3 group-hover:scale-110 transition-transform">
                <svg className="w-6 h-6 text-slate-400 group-hover:text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
              </div>
              <p className="text-sm font-semibold text-slate-600">Attachment Protocol</p>
              <p className="text-xs text-slate-400 mt-1">Upload technical blueprints, cost sheets, or requirement docs</p>
            </div>

            {uploadedFiles.length > 0 && (
              <div className="space-y-2 pt-2">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Active Attachments</p>
                <div className="max-h-40 overflow-auto space-y-2 pr-1">
                  {uploadedFiles.map((file, i) => (
                    <div key={i} className="flex items-center justify-between bg-slate-50 border border-slate-100 p-2 px-3 rounded-lg text-[11px] animate-in fade-in slide-in-from-left-2">
                      <div className="flex items-center gap-2 truncate flex-1">
                         <svg className="w-3.5 h-3.5 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
                         <span className="truncate font-medium text-slate-600">{file.name}</span>
                      </div>
                      <button onClick={() => setUploadedFiles(prev => prev.filter((_, idx) => idx !== i))} className="text-slate-300 hover:text-red-500 ml-2">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Right: Analysis Result View */}
        <div className="space-y-4">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm min-h-[400px]">
            <h3 className="font-bold mb-6 flex items-center gap-2 text-slate-800">
               <div className="w-8 h-8 rounded-lg bg-emerald-50 flex items-center justify-center">
                <svg className="w-4 h-4 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg>
              </div>
              AI Synthesis Report
            </h3>

            {!currentInsights ? (
              <div className="flex flex-col items-center justify-center h-64 text-slate-400 space-y-3">
                <div className="w-12 h-12 border-2 border-slate-100 rounded-full flex items-center justify-center border-t-blue-500 animate-spin-slow">
                   <div className="w-8 h-8 bg-slate-50 rounded-full"></div>
                </div>
                <p className="text-sm font-medium">Awaiting analysis trigger...</p>
              </div>
