import React, { useState } from 'react';
import { ProcessNode, NodeInsights } from '../types';
import { analyzeProcessData, GroundingLink } from '../services/geminiService';

interface InsightsProps {
  nodes: ProcessNode[];
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
  insightsMap: Record<string, NodeInsights>;
  setInsightsMap: React.Dispatch<React.SetStateAction<Record<string, NodeInsights>>>;
}

const Insights: React.FC<InsightsProps> = ({ nodes, selectedNodeId, setSelectedNodeId, insightsMap, setInsightsMap }) => {
  const [inputText, setInputText] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [uploadedFiles, setUploadedFiles] = useState<File[]>([]);
  const [currentLinks, setCurrentLinks] = useState<GroundingLink[]>([]);
  const [lastResponseText, setLastResponseText] = useState<string>('');

  const currentNode = nodes.find(n => n.id === selectedNodeId);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      setUploadedFiles(prev => [...prev, ...Array.from(e.target.files!)]);
    }
  };

  const handleAnalyze = async () => {
    if (!currentNode) return;
    setIsAnalyzing(true);

    // Explicitly link the context to the selected node
    const fileContext = uploadedFiles.map(f => f.name).join(', ');
    const rawContext = `Selected Step: ${currentNode.title}. Description: ${currentNode.description}. Files Attached: ${fileContext || 'None'}. User Input Context: ${inputText}`;

    // Get current location if possible for Maps grounding
    let location = undefined;
    try {
      if ('geolocation' in navigator) {
        const pos = await new Promise<GeolocationPosition>((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));
        location = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
      }
    } catch (e) { console.debug("Location blocked"); }

    const result = await analyzeProcessData(currentNode.title, rawContext, inputText || "Provide a comprehensive analysis of this process step, including requirements and resource mapping.", location);

    if (result) {
      setLastResponseText(result.text);
      setCurrentLinks(result.links);

      // Attempt to parse text if JSON was forced (backward compatibility with original spec)
      try {
        const parsed = JSON.parse(result.text);
        setInsightsMap(prev => ({
          ...prev,
          [currentNode.id]: { nodeId: currentNode.id, ...parsed }
        }));
      } catch (e) {
        // If not JSON, we can still show the text and links
        console.debug("Response was natural language, showing grounding.");
      }
    }
    setIsAnalyzing(false);
  };

  const StepSelector = () => (
    <div className="flex items-center gap-3 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 shadow-sm">
      <label htmlFor="step-select" className="text-xs font-bold text-slate-400 uppercase tracking-tight">Focus Node:</label>
      <select 
        id="step-select"
        value={selectedNodeId || ''}
        onChange={(e) => setSelectedNodeId(e.target.value || null)}
        className="bg-transparent text-sm font-bold text-slate-800 focus:outline-none cursor-pointer min-w-[200px]"
      >
        <option value="">-- Select Step to Analyze --</option>
        {nodes.map(node => (
          <option key={node.id} value={node.id}>
            {node.title || 'Untitled Step'}
          </option>
        ))}
      </select>
    </div>
  );

  if (!selectedNodeId && nodes.length > 0) {
    return (
      <div className="h-full flex flex-col p-6 space-y-6">
        <div className="flex items-center justify-between border-b pb-4">
           <h2 className="text-2xl font-bold text-slate-800">Process Insights</h2>
           <StepSelector />
        </div>
        <div className="flex-1 flex items-center justify-center text-slate-400 flex-col gap-4 bg-white rounded-2xl border border-dashed border-slate-200">
          <svg className="w-16 h-16 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          <div className="text-center">
            <p className="text-lg font-medium text-slate-600">Contextual Data Targeting</p>
            <p className="text-sm">Select a process step above to link your data and files to a specific phase.</p>
          </div>
        </div>
      </div>
    );
  }

  const currentInsights = insightsMap[selectedNodeId!];

  return (
    <div className="h-full flex flex-col p-6 space-y-6 overflow-auto">
      <div className="flex items-center justify-between border-b pb-4 sticky top-0 bg-slate-50/80 backdrop-blur-sm z-10">
        <div className="flex flex-col">
          <h2 className="text-2xl font-bold text-slate-800 tracking-tight">Intelligence Mapping</h2>
          <p className="text-slate-500 text-xs">Matching context to: <span className="text-blue-600 font-bold">{currentNode?.title}</span></p>
        </div>

        <div className="flex items-center gap-4">
          <StepSelector />
          <button 
            onClick={handleAnalyze}
            disabled={isAnalyzing}
            className={`px-6 py-2 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 disabled:opacity-50 flex items-center gap-2 transition-all shadow-lg shadow-blue-500/20 active:scale-95`}
          >
            {isAnalyzing ? (
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
            ) : 'Analyze Context'}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 pb-10">
        <div className="space-y-4">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
            <h3 className="font-bold flex items-center gap-2 text-slate-800">
              <div className="w-8 h-8 rounded-lg bg-blue-50 flex items-center justify-center">
                <svg className="w-4 h-4 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              </div>
              Step-Specific Context
            </h3>

            <textarea 
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder={`Add notes, constraints or queries specifically for ${currentNode?.title}...`}
              className="w-full h-44 p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-4 focus:ring-blue-500/10 transition-all resize-none outline-none"
            />

            <div className="border-2 border-dashed border-slate-200 rounded-xl p-8 text-center hover:bg-blue-50/30 hover:border-blue-200 transition-all cursor-pointer relative group">
              <input type="file" multiple onChange={handleFileUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
              <p className="text-sm font-semibold text-slate-600 group-hover:text-blue-600">Map Files to This Step</p>
              <p className="text-xs text-slate-400 mt-1">Upload specs or blueprints specifically for {currentNode?.title}</p>
            </div>

            {uploadedFiles.length > 0 && (
              <div className="space-y-2 pt-2">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Targeted Files</p>
                <div className="max-h-40 overflow-auto space-y-2 pr-1">
                  {uploadedFiles.map((file, i) => (
                    <div key={i} className="flex items-center justify-between bg-slate-50 border border-slate-100 p-2 px-3 rounded-lg text-[11px]">
                      <span className="truncate font-medium text-slate-600">{file.name}</span>
                      <button onClick={() => setUploadedFiles(prev => prev.filter((_, idx) => idx !== i))} className="text-slate-300 hover:text-red-500"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="space-y-4">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm min-h-[400px]">
            <h3 className="font-bold mb-4 flex items-center gap-2 text-slate-800">
               <div className="w-8 h-8 rounded-lg bg-emerald-50 flex items-center justify-center">
                <svg className="w-4 h-4 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" /></svg>
              </div>
              Verified Intelligence Output
            </h3>

            {!lastResponseText && !currentInsights ? (
              <div className="flex flex-col items-center justify-center h-64 text-slate-400 space-y-3">
                <div className="w-10 h-10 border-2 border-slate-100 rounded-full border-t-blue-500 animate-spin"></div>
                <p className="text-sm font-medium">Awaiting analysis for {currentNode?.title}...</p>
              </div>
            ) : (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
                <div className="prose prose-slate prose-xs max-w-none text-slate-600 text-sm leading-relaxed">
                  {lastResponseText.split('\n').map((line, i) => (
                    <p key={i} className="mb-2">{line}</p>
                  ))}
                </div>

                {currentLinks.length > 0 && (
                  <div className="pt-4 border-t border-slate-100">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Verified Grounding Sources</h4>
                    <div className="grid grid-cols-1 gap-2">
                      {currentLinks.map((link, i) => (
                        <a 
                          key={i} 
                          href={link.uri} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="flex items-center gap-3 p-3 bg-blue-50 border border-blue-100 rounded-xl hover:bg-blue-100 transition-colors text-blue-700"
                        >
                          <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                          <span className="text-xs font-bold truncate">{link.title || link.uri}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

