import React, { useState, useCallback } from 'react';
import { PageView, ProcessNode, Connection, NodeInsights } from './types';
import Sidebar from './components/Sidebar';
import Editor from './components/Editor';
import Insights from './components/Insights';
import Report from './components/Report';
import Simulation from './components/Simulation';

// Define interface for draft context
interface NodeDraft {
  inputText: string;
  files: File[];
}

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageView>('editor');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [projectTitle, setProjectTitle] = useState('Process Strategy Master Plan');

  const [nodes, setNodes] = useState<ProcessNode[]>([]);
  const [connections, setConnections] = useState<Connection[]>([]);
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [insightsMap, setInsightsMap] = useState<Record<string, NodeInsights>>({});

  // Store the user inputs/files per node
  const [nodeDrafts, setNodeDrafts] = useState<Record<string, NodeDraft>>({});

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const addNode = useCallback((x: number = 100, y: number = 100, layer: number = 0) => {
    const newNode: ProcessNode = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Process Step',
      description: 'Define the objectives for this specific task...',
      x,
      y,
      width: 240,
      height: 120,
      color: '#ffffff',
      slots: [
        { id: Math.random().toString(36).substr(2, 9), label: 'Primary Operation', type: 'task' }
      ],
      layer,
      status: 'idle'
    };
    setNodes(prev => [...prev, newNode]);
    // Initialize draft for the new node
    setNodeDrafts(prev => ({ ...prev, [newNode.id]: { inputText: '', files: [] } }));
  }, []);

  const updateNode = useCallback((id: string, updates: Partial<ProcessNode>) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, ...updates } : n));
  }, []);

  const deleteNode = useCallback((id: string) => {
    setNodes(prev => prev.filter(n => n.id !== id));
    setConnections(prev => prev.filter(c => c.sourceNodeId !== id && c.targetNodeId !== id));
    setNodeDrafts(prev => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
    if (selectedNodeId === id) setSelectedNodeId(null);
  }, [selectedNodeId]);

  const addConnection = useCallback((conn: Connection) => {
    setConnections(prev => [...prev, conn]);
  }, []);

  const updateConnection = useCallback((id: string, updates: Partial<Connection>) => {
    setConnections(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  }, []);

  const deleteConnection = useCallback((id: string) => {
    setConnections(prev => prev.filter(c => c.id !== id));
  }, []);

  const renderPage = () => {
    switch (activePage) {
      case 'editor':
        return (
          <Editor 
            nodes={nodes} 
            connections={connections} 
            onAddNode={addNode} 
            onUpdateNode={updateNode} 
            onDeleteNode={deleteNode}
            onAddConnection={addConnection}
            onUpdateConnection={updateConnection}
            onDeleteConnection={deleteConnection}
            projectTitle={projectTitle}
            setProjectTitle={setProjectTitle}
            selectedNodeId={selectedNodeId}
            setSelectedNodeId={setSelectedNodeId}
          />
        );
      case 'insights':
        return (
          <Insights 
            nodes={nodes}
            selectedNodeId={selectedNodeId}
            setSelectedNodeId={setSelectedNodeId}
            insightsMap={insightsMap}
            setInsightsMap={setInsightsMap}
            nodeDrafts={nodeDrafts}
            setNodeDrafts={setNodeDrafts}
          />
        );
      case 'simulation':
        return (
          <Simulation 
            nodes={nodes} 
            connections={connections}
            insightsMap={insightsMap}
            setNodes={setNodes}
          />
        );
      case 'report':
        return (
          <Report 
            nodes={nodes} 
            connections={connections} 
            insightsMap={insightsMap}
            projectTitle={projectTitle}
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 text-slate-900 overflow-hidden font-sans">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={toggleSidebar} 
        activePage={activePage} 
        setActivePage={setActivePage} 
      />

      <main className="flex-1 flex flex-col transition-all duration-300">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-40 shadow-sm">
          <div className="flex items-center gap-4">
            <button 
              onClick={toggleSidebar}
              className="p-2 hover:bg-slate-100 rounded-lg transition-colors border border-transparent hover:border-slate-200"
            >
              <svg className="w-6 h-6 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <h1 className="text-xl font-bold bg-gradient-to-br from-blue-700 to-indigo-700 bg-clip-text text-transparent tracking-tight">
              {projectTitle}
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-700 rounded-full text-xs font-bold border border-emerald-100 shadow-sm">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
              Live Sync
            </div>
            <div className="w-10 h-10 rounded-xl bg-slate-900 overflow-hidden border-2 border-white shadow-lg">
              <img src="https://picsum.photos/40/40?grayscale" alt="User profile" />
            </div>
          </div>
        </header>

        <div className="flex-1 relative overflow-hidden bg-slate-100/50">
          {renderPage()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ProcessNode, NodeInsights } from '../types';
import { analyzeProcessData, GroundingLink } from '../services/geminiService';

interface NodeDraft {
  inputText: string;
  files: File[];
}

interface InsightsProps {
  nodes: ProcessNode[];
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
  insightsMap: Record<string, NodeInsights>;
  setInsightsMap: React.Dispatch<React.SetStateAction<Record<string, NodeInsights>>>;
  nodeDrafts: Record<string, NodeDraft>;
  setNodeDrafts: React.Dispatch<React.SetStateAction<Record<string, NodeDraft>>>;
}

const Insights: React.FC<InsightsProps> = ({ 
  nodes, 
  selectedNodeId, 
  setSelectedNodeId, 
  insightsMap, 
  setInsightsMap,
  nodeDrafts,
  setNodeDrafts
}) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [currentLinks, setCurrentLinks] = useState<GroundingLink[]>([]);
  const [lastResponseText, setLastResponseText] = useState<string>('');

  const currentNode = nodes.find(n => n.id === selectedNodeId);

  // Get draft for the selected node or default empty
  const currentDraft = selectedNodeId ? nodeDrafts[selectedNodeId] || { inputText: '', files: [] } : { inputText: '', files: [] };

  const updateDraftText = (text: string) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: { ...prev[selectedNodeId], inputText: text }
    }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && selectedNodeId) {
      const newFiles = Array.from(e.target.files);
      setNodeDrafts(prev => ({
        ...prev,
        [selectedNodeId]: { ...prev[selectedNodeId], files: [...prev[selectedNodeId].files, ...newFiles] }
      }));
    }
  };

  const removeFile = (index: number) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: {
        ...prev[selectedNodeId],
        files: prev[selectedNodeId].files.filter((_, i) => i !== index)
      }
    }));
  };

  const handleAnalyze = async () => {
    if (!currentNode || !selectedNodeId) return;
    setIsAnalyzing(true);

    const fileContext = currentDraft.files.map(f => f.name).join(', ');
    const rawContext = `Target Node: ${currentNode.title}. Description: ${currentNode.description}. Files for this node: ${fileContext || 'None'}. Node-specific Context: ${currentDraft.inputText}`;

    let location = undefined;
    try {
      if ('geolocation' in navigator) {
        const pos = await new Promise<GeolocationPosition>((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));
        location = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
      }
    } catch (e) { console.debug("Location restricted"); }

    const result = await analyzeProcessData(currentNode.title, rawContext, currentDraft.inputText || "Analyze this process step and provide actionable technical requirements and resource needs.", location);

    if (result) {
      setLastResponseText(result.text);
      setCurrentLinks(result.links);

      // Store result mapped strictly to this node ID
      try {
        const parsed = JSON.parse(result.text);
        setInsightsMap(prev => ({
          ...prev,
          [selectedNodeId]: { nodeId: selectedNodeId, ...parsed }
        }));
      } catch (e) {
        // Handle natural language responses by storing the text as a summary
        setInsightsMap(prev => ({
          ...prev,
          [selectedNodeId]: { 
            nodeId: selectedNodeId, 
            summary: result.text, 
            requirements: [], 
            resources: [], 
            executionStyle: 'Standard' 
          }
        }));
      }
    }
    setIsAnalyzing(false);
  };

  const StepSelector = () => (
    <div className="flex items-center gap-3 bg-white border border-slate-200 rounded-xl px-4 py-2 shadow-sm">
      <label htmlFor="step-select" className="text-xs font-bold text-slate-400 uppercase tracking-tight">Active Node:</label>
      <select 
        id="step-select"
        value={selectedNodeId || ''}
        onChange={(e) => {
          setSelectedNodeId(e.target.value || null);
          setLastResponseText(''); // Clear previous display on switch
          setCurrentLinks([]);
        }}
        className="bg-transparent text-sm font-bold text-slate-800 focus:outline-none cursor-pointer min-w-[200px]"
      >
        <option value="">-- Choose Target Node --</option>
        {nodes.map(node => (
          <option key={node.id} value={node.id}>
            {node.title || 'Untitled Step'}
          </option>
        ))}
      </select>
    </div>
  );

  // If no step selected, prompt to pick one
  if (!selectedNodeId && nodes.length > 0) {
    return (
      <div className="h-full flex flex-col p-6 space-y-6">
        <div className="flex items-center justify-between border-b pb-4">
           <h2 className="text-2xl font-bold text-slate-800">Process Insights</h2>
           <StepSelector />
        </div>
        <div className="flex-1 flex items-center justify-center text-slate-400 flex-col gap-4 bg-white rounded-2xl border border-dashed border-slate-200">
          <svg className="w-16 h-16 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          <div className="text-center">
            <p className="text-lg font-medium text-slate-600">Select a Step to Begin Analysis</p>
            <p className="text-sm">Data entered for each step is isolated and strictly matched to that node.</p>
          </div>
        </div>
      </div>
    );
  }

  const currentInsights = selectedNodeId ? insightsMap[selectedNodeId] : null;

  return (
    <div className="h-full flex flex-col p-6 space-y-6 overflow-auto">
      <div className="flex items-center justify-between border-b pb-4 sticky top-0 bg-slate-50/90 backdrop-blur-md z-10">
        <div className="flex flex-col">
          <h2 className="text-2xl font-bold text-slate-800 tracking-tight">Step Intelligence</h2>
          <p className="text-slate-500 text-xs">Matching Context to: <span className="text-blue-600 font-bold uppercase">{currentNode?.title}</span></p>
        </div>

        <div className="flex items-center gap-4">
          <StepSelector />
          <button 
            onClick={handleAnalyze}
            disabled={isAnalyzing || !selectedNodeId}
            className={`px-6 py-2 bg-slate-900 text-white rounded-xl font-bold hover:bg-black disabled:opacity-50 flex items-center gap-2 transition-all shadow-lg active:scale-95`}
          >
            {isAnalyzing ? (
              <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
            ) : 'Run Deep Analysis'}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 pb-10">
        {/* Left: Isolated Data Entry */}
        <div className="space-y-4">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
            <h3 className="font-bold flex items-center gap-2 text-slate-800">
              <div className="w-8 h-8 rounded-lg bg-blue-50 flex items-center justify-center">
                <svg className="w-4 h-4 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </div>
              Isolated Data Entry: {currentNode?.title}
            </h3>

            <textarea 
              value={currentDraft.inputText}
              onChange={(e) => updateDraftText(e.target.value)}
              placeholder={`Enter technical specs or component requirements for ${currentNode?.title}...`}
              className="w-full h-48 p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all resize-none outline-none"
            />

            <div className="border-2 border-dashed border-slate-200 rounded-xl p-8 text-center hover:bg-slate-50 hover:border-blue-300 transition-all cursor-pointer relative group">
              <input type="file" multiple onChange={handleFileUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
              <p className="text-sm font-bold text-slate-600">Step-Specific Blueprint</p>
              <p className="text-xs text-slate-400 mt-1">Files uploaded here are only analyzed with {currentNode?.title}</p>
            </div>

            {currentDraft.files.length > 0 && (
              <div className="space-y-2 pt-2">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Active Step Files</p>
                <div className="max-h-40 overflow-auto space-y-2 pr-1">
                  {currentDraft.files.map((file, i) => (
                    <div key={i} className="flex items-center justify-between bg-slate-50 border border-slate-100 p-2 px-3 rounded-lg text-[11px] animate-in slide-in-from-left-2">
                      <span className="truncate font-medium text-slate-700">{file.name}</span>
                      <button onClick={() => removeFile(i)} className="text-slate-300 hover:text-red-500 transition-colors"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Right: Specific AI Result */}
        <div className="space-y-4">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm min-h-[400px]">
            <h3 className="font-bold mb-4 flex items-center gap-2 text-slate-800">
               <div className="w-8 h-8 rounded-lg bg-emerald-50 flex items-center justify-center">
                <svg className="w-4 h-4 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              </div>
              Verified Intelligence: {currentNode?.title}
            </h3>

            {!lastResponseText && !currentInsights ? (
              <div className="flex flex-col items-center justify-center h-64 text-slate-300 space-y-3">
                <div className="w-12 h-12 rounded-full border-2 border-slate-100 border-t-emerald-400 animate-spin"></div>
                <p className="text-sm font-medium">Awaiting analysis for this specific step...</p>
              </div>
            ) : (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
                <div className="bg-slate-50 border border-slate-100 p-4 rounded-xl prose prose-slate max-w-none text-slate-700 text-sm leading-relaxed">
                  {(lastResponseText || currentInsights?.summary || '').split('\n').map((line, i) => (
                    <p key={i} className="mb-2">{line}</p>
                  ))}
                </div>

                {currentLinks.length > 0 && (
                  <div className="pt-4 border-t border-slate-100">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Grounding & Verified Sources</h4>
                    <div className="grid grid-cols-1 gap-2">
                      {currentLinks.map((link, i) => (
                        <a 
                          key={i} 
                          href={link.uri} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="flex items-center gap-3 p-3 bg-blue-50 border border-blue-100 rounded-xl hover:bg-blue-100 transition-all text-blue-700 hover:translate-x-1"
                        >
                          <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                          <span className="text-xs font-bold truncate">{link.title || link.uri}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

