import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ProcessNode, Connection, SlotType, ConnectionType } from '../types';

interface EditorProps {
  nodes: ProcessNode[];
  connections: Connection[];
  onAddNode: (x?: number, y?: number, layer?: number) => void;
  onUpdateNode: (id: string, updates: Partial<ProcessNode>) => void;
  onDeleteNode: (id: string) => void;
  onAddConnection: (conn: Connection) => void;
  onUpdateConnection: (id: string, updates: Partial<Connection>) => void;
  onDeleteConnection: (id: string) => void;
  projectTitle: string;
  setProjectTitle: (val: string) => void;
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
}

const COLORS = [
  { name: 'White', value: '#ffffff' },
  { name: 'Blue', value: '#eff6ff' },
  { name: 'Green', value: '#f0fdf4' },
  { name: 'Amber', value: '#fffbeb' },
  { name: 'Red', value: '#fef2f2' },
  { name: 'Slate', value: '#f8fafc' },
];

const CONNECTION_TYPES: { label: string, value: ConnectionType, color: string, dash?: string }[] = [
  { label: 'Dependency', value: 'dependency', color: '#64748b' },
  { label: 'Data Flow', value: 'data-flow', color: '#3b82f6' },
  { label: 'Resource Flow', value: 'resource-flow', color: '#10b981', dash: '5,5' },
  { label: 'Informational', value: 'informational', color: '#f59e0b', dash: '2,2' },
];

const Editor: React.FC<EditorProps> = ({ 
  nodes, connections, onAddNode, onUpdateNode, onDeleteNode, onAddConnection, 
  onUpdateConnection, onDeleteConnection,
  projectTitle, setProjectTitle, selectedNodeId, setSelectedNodeId 
}) => {
  const [isConnecting, setIsConnecting] = useState<{ nodeId: string, slotId: string } | null>(null);
  const [nodeContextMenu, setNodeContextMenu] = useState<{ x: number, y: number, nodeId: string } | null>(null);
  const [lineContextMenu, setLineContextMenu] = useState<{ x: number, y: number, connId: string } | null>(null);
  const [draggingNodeId, setDraggingNodeId] = useState<string | null>(null);
  const dragOffset = useRef({ x: 0, y: 0 });
  const canvasRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const closeMenus = () => {
      setNodeContextMenu(null);
      setLineContextMenu(null);
    };
    window.addEventListener('click', closeMenus);
    return () => window.removeEventListener('click', closeMenus);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (draggingNodeId && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const scrollX = canvasRef.current.scrollLeft;
      const scrollY = canvasRef.current.scrollTop;
      const x = e.clientX - rect.left + scrollX - dragOffset.current.x;
      const y = e.clientY - rect.top + scrollY - dragOffset.current.y;
      const layer = Math.floor(y / 200);
      onUpdateNode(draggingNodeId, { x, y, layer });
    }
  }, [draggingNodeId, onUpdateNode]);

  const handleMouseUp = () => setDraggingNodeId(null);

  const handleNodeMouseDown = (e: React.MouseEvent, nodeId: string) => {
    if (e.button !== 0) return; 
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      setDraggingNodeId(nodeId);
      setSelectedNodeId(nodeId);
      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      dragOffset.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  const handleNodeContextMenu = (e: React.MouseEvent, nodeId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setLineContextMenu(null);
    setNodeContextMenu({ x: e.clientX, y: e.clientY, nodeId });
  };

  const handleLineContextMenu = (e: React.MouseEvent, connId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setNodeContextMenu(null);
    setLineContextMenu({ x: e.clientX, y: e.clientY, connId });
  };

  const handleSlotClick = (e: React.MouseEvent, nodeId: string, slotId: string) => {
    e.stopPropagation();
    if (!isConnecting) {
      setIsConnecting({ nodeId, slotId });
    } else {
      if (isConnecting.nodeId !== nodeId) {
        onAddConnection({
          id: Math.random().toString(36).substr(2, 9),
          sourceNodeId: isConnecting.nodeId,
          sourceSlotId: isConnecting.slotId,
          targetNodeId: nodeId,
          targetSlotId: slotId,
          biDirectional: false,
          type: 'dependency'
        });
      }
      setIsConnecting(null);
    }
  };

  const addSlot = (nodeId: string, type: SlotType) => {
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      onUpdateNode(nodeId, {
        slots: [...node.slots, { id: Math.random().toString(36).substr(2, 9), label: `New ${type}`, type }]
      });
    }
  };

  const activeContextNode = nodes.find(n => n.id === nodeContextMenu?.nodeId);
  const activeContextConn = connections.find(c => c.id === lineContextMenu?.connId);

  // PRECISE UI DIMENSIONS FOR SLOT CENTER CALCULATION
  const HEADER_H = 37;
  const PADDING_T = 12; // from p-3
  const TEXTAREA_H = 48; // from h-12
  const GAP_S = 8; // from space-y-2
  const SLOT_H = 20; // from h-5
  const DOT_CENTER = 10; // vertical center of a 20px slot

  // BASE_Y_OFFSET: The cumulative height from node top to the center of the first slot
  const BASE_Y_OFFSET = HEADER_H + PADDING_T + TEXTAREA_H + GAP_S + DOT_CENTER;

  return (
    <div className="flex flex-col h-full select-none" onMouseMove={handleMouseMove} onMouseUp={handleMouseUp}>
      <div className="bg-white border-b border-slate-200 p-2 flex items-center justify-between shadow-sm z-30">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1 border-r pr-4">
            <input 
              type="text" 
              value={projectTitle}
              onChange={(e) => setProjectTitle(e.target.value)}
              className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500 w-64"
            />
          </div>
          <div className="flex items-center gap-2">
            <button className="px-3 py-1 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-all flex items-center gap-2 shadow-lg shadow-blue-500/10" onClick={() => onAddNode(200, 100 + (nodes.length * 40))}>
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
              New Process Step
            </button>
            <div className="w-[1px] h-6 bg-slate-200 mx-1"></div>
            <button className="p-2 hover:bg-slate-100 rounded text-slate-600 font-bold">B</button>
            <button className="p-2 hover:bg-slate-100 rounded text-slate-600 italic">I</button>
          </div>
        </div>
        <div className="flex items-center gap-3 pr-4">
           <button className="text-xs text-slate-400 font-medium hover:text-slate-600">Export Blueprint</button>
        </div>
      </div>

      <div 
        ref={canvasRef}
        className="flex-1 relative bg-slate-100 overflow-auto canvas-grid"
        style={{
          backgroundImage: 'radial-gradient(circle, #cbd5e1 1px, transparent 1px)',
          backgroundSize: '24px 24px'
        }}
      >
        <div style={{ minWidth: 4000, minHeight: 4000, position: 'relative' }}>
          {[0, 1, 2, 3, 4, 5, 6, 7].map(i => (
            <div key={i} className="absolute w-full border-b border-slate-300 pointer-events-none" style={{ top: i * 200, height: 200 }}>
              <span className="absolute left-4 top-4 text-[10px] font-black text-slate-300 uppercase tracking-widest">PROCESS PHASE {i + 1}</span>
            </div>
          ))}

          <svg className="absolute inset-0 w-full h-full pointer-events-none">
            <defs>
              {CONNECTION_TYPES.map(ct => (
                <marker key={ct.value} id={`arrow-${ct.value}`} markerWidth="10" markerHeight="7" refX="9" refY="3.5" orientation="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill={ct.color} />
                </marker>
              ))}
            </defs>
            {connections.map(conn => {
              const srcNode = nodes.find(n => n.id === conn.sourceNodeId);
              const trgNode = nodes.find(n => n.id === conn.targetNodeId);
              if (!srcNode || !trgNode) return null;

              const srcSlotIdx = srcNode.slots.findIndex(s => s.id === conn.sourceSlotId);
              const trgSlotIdx = trgNode.slots.findIndex(s => s.id === conn.targetSlotId);

              // X: Right/Left edges adjusted for dot position (20px in from border)
              const x1 = srcNode.x + srcNode.width - 20; 
              const y1 = srcNode.y + BASE_Y_OFFSET + (srcSlotIdx * SLOT_H);

              const x2 = trgNode.x + 20;
              const y2 = trgNode.y + BASE_Y_OFFSET + (trgSlotIdx * SLOT_H);

              const connType = CONNECTION_TYPES.find(ct => ct.value === conn.type) || CONNECTION_TYPES[0];

              return (
                <g key={conn.id}>
                  <path 
                    d={`M ${x1} ${y1} C ${x1 + 80} ${y1}, ${x2 - 80} ${y2}, ${x2} ${y2}`}
                    stroke={connType.color}
                    strokeWidth="3"
                    strokeDasharray={connType.dash || '0'}
                    fill="none"
                    markerEnd={`url(#arrow-${connType.value})`}
                    className="pointer-events-auto cursor-pointer hover:stroke-blue-400 transition-colors"
                    onContextMenu={(e) => handleLineContextMenu(e, conn.id)}
                  />
                </g>
              );
            })}
          </svg>

          {nodes.map(node => (
            <div
              key={node.id}
              onMouseDown={(e) => handleNodeMouseDown(e, node.id)}
              onContextMenu={(e) => handleNodeContextMenu(e, node.id)}
              className={`absolute rounded-xl border-2 shadow-sm flex flex-col cursor-move transition-shadow select-none ${selectedNodeId === node.id ? 'border-blue-500 ring-4 ring-blue-500/10 z-20' : 'border-slate-300 hover:border-slate-400 z-10'}`}
              style={{ 
                left: node.x, 
                top: node.y, 
                width: node.width,
                minHeight: node.height,
                backgroundColor: node.color || '#ffffff'
              }}
            >
              <div className="bg-white/50 backdrop-blur-sm border-b border-slate-200 px-3 py-2 flex items-center justify-between rounded-t-xl h-[37px]">
                <input 
                  className="font-bold text-sm bg-transparent w-full focus:outline-none"
                  value={node.title}
                  onChange={(e) => onUpdateNode(node.id, { title: e.target.value })}
                  onMouseDown={(e) => e.stopPropagation()}
                />
                <button 
                  onClick={(e) => { e.stopPropagation(); addSlot(node.id, 'task'); }}
                  className="w-5 h-5 flex items-center justify-center bg-slate-100 hover:bg-slate-200 rounded text-slate-500"
                >
                  <span className="text-xs">+</span>
                </button>
              </div>

              <div className="p-3 space-y-2">
                <textarea 
                  className="text-[11px] text-slate-600 w-full resize-none h-12 border-none bg-transparent focus:outline-none placeholder:italic"
                  placeholder="Describe step purpose..."
                  value={node.description}
                  onChange={(e) => onUpdateNode(node.id, { description: e.target.value })}
                  onMouseDown={(e) => e.stopPropagation()}
                />
                <div className="space-y-0">
                  {node.slots.map(slot => (
                    <div 
                      key={slot.id} 
                      className="flex items-center justify-between text-[11px] h-5"
                      onMouseDown={(e) => e.stopPropagation()}
                    >
                      <div className="flex items-center gap-2 overflow-hidden flex-1">
                        <div className={`w-2 h-2 rounded-full flex-shrink-0 ${slot.type === 'task' ? 'bg-blue-400' : slot.type === 'decision' ? 'bg-amber-400' : 'bg-emerald-400'}`}></div>
                        <input 
                          className="bg-transparent hover:bg-white/60 focus:bg-white rounded px-1 outline-none w-full truncate"
                          value={slot.label}
                          onChange={(e) => {
                            const newSlots = node.slots.map(s => s.id === slot.id ? { ...s, label: e.target.value } : s);
                            onUpdateNode(node.id, { slots: newSlots });
                          }}
                        />
                      </div>
                      <button 
                        onClick={(e) => handleSlotClick(e, node.id, slot.id)}
                        className={`w-4 h-4 rounded-full border border-slate-300 flex items-center justify-center transition-all ${isConnecting?.slotId === slot.id ? 'bg-blue-500 border-blue-500 scale-150 shadow-lg' : 'bg-white hover:bg-blue-50 hover:scale-110'}`}
                      >
                        <div className={`w-1.5 h-1.5 rounded-full ${isConnecting?.slotId === slot.id ? 'bg-white' : 'bg-slate-300'}`}></div>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>

        {nodeContextMenu && activeContextNode && (
          <div className="fixed z-50 bg-white border border-slate-200 shadow-2xl rounded-xl p-4 w-64 space-y-4" style={{ left: nodeContextMenu.x, top: nodeContextMenu.y }} onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center"><span className="text-xs font-black text-slate-400 uppercase">Edit Box</span><button onClick={() => setNodeContextMenu(null)}>×</button></div>
            <div className="grid grid-cols-2 gap-2">
              <div className="flex flex-col"><span className="text-[9px] text-slate-400 uppercase font-bold">Width</span><input type="number" className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-xs" value={activeContextNode.width} onChange={(e) => onUpdateNode(activeContextNode.id, { width: parseInt(e.target.value) || 200 })} /></div>
              <div className="flex flex-col"><span className="text-[9px] text-slate-400 uppercase font-bold">Height</span><input type="number" className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-xs" value={activeContextNode.height} onChange={(e) => onUpdateNode(activeContextNode.id, { height: parseInt(e.target.value) || 100 })} /></div>
            </div>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => <button key={c.value} onClick={() => onUpdateNode(activeContextNode.id, { color: c.value })} className={`w-6 h-6 rounded-full border transition-all ${activeContextNode.color === c.value ? 'ring-2 ring-blue-500 ring-offset-1 scale-110 shadow-md' : 'hover:scale-105'}`} style={{ backgroundColor: c.value }} />)}
            </div>
            <button onClick={() => { onDeleteNode(activeContextNode.id); setNodeContextMenu(null); }} className="w-full bg-red-50 text-red-600 text-xs py-2 rounded-lg font-bold hover:bg-red-100 transition-colors">Delete Step</button>
          </div>
        )}

        {lineContextMenu && activeContextConn && (
          <div className="fixed z-50 bg-white border border-slate-200 shadow-2xl rounded-xl p-4 w-56 space-y-3" style={{ left: lineContextMenu.x, top: lineContextMenu.y }} onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center text-xs font-black text-slate-400 uppercase tracking-tighter">Connection Type</div>
            <div className="space-y-1">
              {CONNECTION_TYPES.map(ct => (
                <button 
                  key={ct.value}
                  onClick={() => { onUpdateConnection(activeContextConn.id, { type: ct.value }); setLineContextMenu(null); }}
                  className={`w-full text-left px-3 py-2 text-xs rounded-lg flex items-center gap-2 hover:bg-slate-50 transition-colors ${activeContextConn.type === ct.value ? 'bg-blue-50 text-blue-700 font-bold' : 'text-slate-600'}`}
                >
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: ct.color }}></div>
                  {ct.label}
                </button>
              ))}
            </div>
            <div className="border-t pt-2 mt-2">
              <button onClick={() => { onDeleteConnection(activeContextConn.id); setLineContextMenu(null); }} className="w-full bg-slate-50 text-slate-600 text-[11px] py-2 rounded-lg font-bold hover:bg-red-50 hover:text-red-600 transition-colors">Delete Relationship</button>
            </div>
          </div>
        )}
      </div>

      <div className="p-3 bg-white border-t flex justify-between items-center text-xs text-slate-500 z-10">
        <div className="flex gap-4">
          {CONNECTION_TYPES.map(ct => (
            <div key={ct.value} className="flex items-center gap-1">
              <div className="w-3 h-[3px] rounded-full" style={{ backgroundColor: ct.color }}></div> {ct.label}
            </div>
          ))}
        </div>
        <p className="font-medium italic">Isolated Data Architecture • Per-Node Context Processing • Precision Slot Connectivity</p>
      </div>
    </div>
  );
};

export default Editor;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ProcessNode, Connection, SlotType, ConnectionType } from '../types';

interface EditorProps {
  nodes: ProcessNode[];
  connections: Connection[];
  onAddNode: (x?: number, y?: number, layer?: number) => void;
  onUpdateNode: (id: string, updates: Partial<ProcessNode>) => void;
  onDeleteNode: (id: string) => void;
  onAddConnection: (conn: Connection) => void;
  onUpdateConnection: (id: string, updates: Partial<Connection>) => void;
  onDeleteConnection: (id: string) => void;
  projectTitle: string;
  setProjectTitle: (val: string) => void;
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
}

const COLORS = [
  { name: 'White', value: '#ffffff' },
  { name: 'Blue', value: '#eff6ff' },
  { name: 'Green', value: '#f0fdf4' },
  { name: 'Amber', value: '#fffbeb' },
  { name: 'Red', value: '#fef2f2' },
  { name: 'Slate', value: '#f8fafc' },
];

const CONNECTION_TYPES: { label: string, value: ConnectionType, color: string, dash?: string }[] = [
  { label: 'Dependency', value: 'dependency', color: '#64748b' },
  { label: 'Data Flow', value: 'data-flow', color: '#3b82f6' },
  { label: 'Resource Flow', value: 'resource-flow', color: '#10b981', dash: '5,5' },
  { label: 'Informational', value: 'informational', color: '#f59e0b', dash: '2,2' },
];

const Editor: React.FC<EditorProps> = ({ 
  nodes, connections, onAddNode, onUpdateNode, onDeleteNode, onAddConnection, 
  onUpdateConnection, onDeleteConnection,
  projectTitle, setProjectTitle, selectedNodeId, setSelectedNodeId 
}) => {
  const [isConnecting, setIsConnecting] = useState<{ nodeId: string, slotId: string } | null>(null);
  const [nodeContextMenu, setNodeContextMenu] = useState<{ x: number, y: number, nodeId: string } | null>(null);
  const [lineContextMenu, setLineContextMenu] = useState<{ x: number, y: number, connId: string } | null>(null);
  const [slotContextMenu, setSlotContextMenu] = useState<{ x: number, y: number, nodeId: string, slotId: string } | null>(null);
  const [draggingNodeId, setDraggingNodeId] = useState<string | null>(null);
  const dragOffset = useRef({ x: 0, y: 0 });
  const canvasRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const closeMenus = () => {
      setNodeContextMenu(null);
      setLineContextMenu(null);
      setSlotContextMenu(null);
    };
    window.addEventListener('click', closeMenus);
    return () => window.removeEventListener('click', closeMenus);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (draggingNodeId && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      const scrollX = canvasRef.current.scrollLeft;
      const scrollY = canvasRef.current.scrollTop;
      const x = e.clientX - rect.left + scrollX - dragOffset.current.x;
      const y = e.clientY - rect.top + scrollY - dragOffset.current.y;
      const layer = Math.floor(y / 200);
      onUpdateNode(draggingNodeId, { x, y, layer });
    }
  }, [draggingNodeId, onUpdateNode]);

  const handleMouseUp = () => setDraggingNodeId(null);

  const handleNodeMouseDown = (e: React.MouseEvent, nodeId: string) => {
    if (e.button !== 0) return; 
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      setDraggingNodeId(nodeId);
      setSelectedNodeId(nodeId);
      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      dragOffset.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  const handleNodeContextMenu = (e: React.MouseEvent, nodeId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setLineContextMenu(null);
    setSlotContextMenu(null);
    setNodeContextMenu({ x: e.clientX, y: e.clientY, nodeId });
  };

  const handleSlotContextMenu = (e: React.MouseEvent, nodeId: string, slotId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setNodeContextMenu(null);
    setLineContextMenu(null);
    setSlotContextMenu({ x: e.clientX, y: e.clientY, nodeId, slotId });
  };

  const handleLineContextMenu = (e: React.MouseEvent, connId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setNodeContextMenu(null);
    setSlotContextMenu(null);
    setLineContextMenu({ x: e.clientX, y: e.clientY, connId });
  };

  const handleSlotClick = (e: React.MouseEvent, nodeId: string, slotId: string) => {
    e.stopPropagation();
    if (!isConnecting) {
      setIsConnecting({ nodeId, slotId });
    } else {
      if (isConnecting.nodeId !== nodeId) {
        onAddConnection({
          id: Math.random().toString(36).substr(2, 9),
          sourceNodeId: isConnecting.nodeId,
          sourceSlotId: isConnecting.slotId,
          targetNodeId: nodeId,
          targetSlotId: slotId,
          biDirectional: false,
          type: 'dependency'
        });
      }
      setIsConnecting(null);
    }
  };

  const addSlot = (nodeId: string, type: SlotType) => {
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      onUpdateNode(nodeId, {
        slots: [...node.slots, { id: Math.random().toString(36).substr(2, 9), label: `New ${type}`, type }]
      });
    }
  };

  const deleteSlot = (nodeId: string, slotId: string) => {
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      // 1. Remove connections involving this slot
      connections
        .filter(c => (c.sourceNodeId === nodeId && c.sourceSlotId === slotId) || (c.targetNodeId === nodeId && c.targetSlotId === slotId))
        .forEach(c => onDeleteConnection(c.id));

      // 2. Remove the slot from the node
      onUpdateNode(nodeId, {
        slots: node.slots.filter(s => s.id !== slotId)
      });
    }
    setSlotContextMenu(null);
  };

  const activeContextNode = nodes.find(n => n.id === nodeContextMenu?.nodeId);
  const activeContextConn = connections.find(c => c.id === lineContextMenu?.connId);

  // PRECISE UI DIMENSIONS FOR SLOT CENTER CALCULATION
  const HEADER_H = 37;
  const PADDING_T = 12; // from p-3
  const TEXTAREA_H = 48; // from h-12
  const GAP_S = 8; // from space-y-2
  const SLOT_H = 20; // from h-5
  const DOT_CENTER = 3; // vertical center of a 20px slot

  const BASE_Y_OFFSET = HEADER_H + PADDING_T + TEXTAREA_H + GAP_S + DOT_CENTER;

  return (
    <div className="flex flex-col h-full select-none" onMouseMove={handleMouseMove} onMouseUp={handleMouseUp}>
      <div className="bg-white border-b border-slate-200 p-2 flex items-center justify-between shadow-sm z-30">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1 border-r pr-4">
            <input 
              type="text" 
              value={projectTitle}
              onChange={(e) => setProjectTitle(e.target.value)}
              className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-500 w-64"
            />
          </div>
          <div className="flex items-center gap-2">
            <button className="px-3 py-1 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-all flex items-center gap-2 shadow-lg shadow-blue-500/10" onClick={() => onAddNode(200, 100 + (nodes.length * 40))}>
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
              New Process Step
            </button>
            <div className="w-[1px] h-6 bg-slate-200 mx-1"></div>
            <button className="p-2 hover:bg-slate-100 rounded text-slate-600 font-bold">B</button>
            <button className="p-2 hover:bg-slate-100 rounded text-slate-600 italic">I</button>
          </div>
        </div>
        <div className="flex items-center gap-3 pr-4">
           <button className="text-xs text-slate-400 font-medium hover:text-slate-600">Export Blueprint</button>
        </div>
      </div>

      <div 
        ref={canvasRef}
        className="flex-1 relative bg-slate-100 overflow-auto canvas-grid"
        style={{
          backgroundImage: 'radial-gradient(circle, #cbd5e1 1px, transparent 1px)',
          backgroundSize: '24px 24px'
        }}
      >
        <div style={{ minWidth: 4000, minHeight: 4000, position: 'relative' }}>
          {[0, 1, 2, 3, 4, 5, 6, 7].map(i => (
            <div key={i} className="absolute w-full border-b border-slate-300 pointer-events-none" style={{ top: i * 200, height: 200 }}>
              <span className="absolute left-4 top-4 text-[10px] font-black text-slate-300 uppercase tracking-widest">PROCESS PHASE {i + 1}</span>
            </div>
          ))}

          <svg className="absolute inset-0 w-full h-full pointer-events-none">
            <defs>
              {CONNECTION_TYPES.map(ct => (
                <marker key={ct.value} id={`arrow-${ct.value}`} markerWidth="10" markerHeight="7" refX="9" refY="3.5" orientation="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill={ct.color} />
                </marker>
              ))}
            </defs>
            {connections.map(conn => {
              const srcNode = nodes.find(n => n.id === conn.sourceNodeId);
              const trgNode = nodes.find(n => n.id === conn.targetNodeId);
              if (!srcNode || !trgNode) return null;

              const srcSlotIdx = srcNode.slots.findIndex(s => s.id === conn.sourceSlotId);
              const trgSlotIdx = trgNode.slots.findIndex(s => s.id === conn.targetSlotId);

              // X: Right/Left edges adjusted for dot position (20px in from border)
              const x1 = srcNode.x + srcNode.width - 20; 
              const y1 = srcNode.y + BASE_Y_OFFSET + (srcSlotIdx * SLOT_H);

              const x2 = trgNode.x + 20;
              const y2 = trgNode.y + BASE_Y_OFFSET + (trgSlotIdx * SLOT_H);

              const connType = CONNECTION_TYPES.find(ct => ct.value === conn.type) || CONNECTION_TYPES[0];

              return (
                <g key={conn.id}>
                  <path 
                    d={`M ${x1} ${y1} C ${x1 + 80} ${y1}, ${x2 - 80} ${y2}, ${x2} ${y2}`}
                    stroke={connType.color}
                    strokeWidth="3"
                    strokeDasharray={connType.dash || '0'}
                    fill="none"
                    markerEnd={`url(#arrow-${connType.value})`}
                    className="pointer-events-auto cursor-pointer hover:stroke-blue-400 transition-colors"
                    onContextMenu={(e) => handleLineContextMenu(e, conn.id)}
                  />
                </g>
              );
            })}
          </svg>

          {nodes.map(node => (
            <div
              key={node.id}
              onMouseDown={(e) => handleNodeMouseDown(e, node.id)}
              onContextMenu={(e) => handleNodeContextMenu(e, node.id)}
              className={`absolute rounded-xl border-2 shadow-sm flex flex-col cursor-move transition-shadow select-none ${selectedNodeId === node.id ? 'border-blue-500 ring-4 ring-blue-500/10 z-20' : 'border-slate-300 hover:border-slate-400 z-10'}`}
              style={{ 
                left: node.x, 
                top: node.y, 
                width: node.width,
                minHeight: node.height,
                backgroundColor: node.color || '#ffffff'
              }}
            >
              <div className="bg-white/50 backdrop-blur-sm border-b border-slate-200 px-3 py-2 flex items-center justify-between rounded-t-xl h-[37px]">
                <input 
                  className="font-bold text-sm bg-transparent w-full focus:outline-none"
                  value={node.title}
                  onChange={(e) => onUpdateNode(node.id, { title: e.target.value })}
                  onMouseDown={(e) => e.stopPropagation()}
                />
                <button 
                  onClick={(e) => { e.stopPropagation(); addSlot(node.id, 'task'); }}
                  className="w-5 h-5 flex items-center justify-center bg-slate-100 hover:bg-slate-200 rounded text-slate-500"
                >
                  <span className="text-xs">+</span>
                </button>
              </div>

              <div className="p-3 space-y-2">
                <textarea 
                  className="text-[11px] text-slate-600 w-full resize-none h-12 border-none bg-transparent focus:outline-none placeholder:italic"
                  placeholder="Describe step purpose..."
                  value={node.description}
                  onChange={(e) => onUpdateNode(node.id, { description: e.target.value })}
                  onMouseDown={(e) => e.stopPropagation()}
                />
                <div className="space-y-0">
                  {node.slots.map(slot => (
                    <div 
                      key={slot.id} 
                      className="flex items-center justify-between text-[11px] h-5 relative group"
                      onMouseDown={(e) => e.stopPropagation()}
                      onContextMenu={(e) => handleSlotContextMenu(e, node.id, slot.id)}
                    >
                      <div className="flex items-center gap-2 overflow-hidden flex-1 pr-4">
                        <div className={`w-2 h-2 rounded-full flex-shrink-0 ${slot.type === 'task' ? 'bg-blue-400' : slot.type === 'decision' ? 'bg-amber-400' : 'bg-emerald-400'}`}></div>
                        <input 
                          className="bg-transparent hover:bg-white/60 focus:bg-white rounded px-1 outline-none w-full truncate"
                          value={slot.label}
                          onChange={(e) => {
                            const newSlots = node.slots.map(s => s.id === slot.id ? { ...s, label: e.target.value } : s);
                            onUpdateNode(node.id, { slots: newSlots });
                          }}
                        />
                      </div>
                      <button 
                        onClick={(e) => handleSlotClick(e, node.id, slot.id)}
                        className={`w-4 h-4 rounded-full border border-slate-300 flex items-center justify-center transition-all ${isConnecting?.slotId === slot.id ? 'bg-blue-500 border-blue-500 scale-150 shadow-lg' : 'bg-white hover:bg-blue-50 hover:scale-110'}`}
                      >
                        <div className={`w-1.5 h-1.5 rounded-full ${isConnecting?.slotId === slot.id ? 'bg-white' : 'bg-slate-300'}`}></div>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>

        {nodeContextMenu && activeContextNode && (
          <div className="fixed z-50 bg-white border border-slate-200 shadow-2xl rounded-xl p-4 w-64 space-y-4" style={{ left: nodeContextMenu.x, top: nodeContextMenu.y }} onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center"><span className="text-xs font-black text-slate-400 uppercase">Edit Box</span><button onClick={() => setNodeContextMenu(null)}>×</button></div>
            <div className="grid grid-cols-2 gap-2">
              <div className="flex flex-col"><span className="text-[9px] text-slate-400 uppercase font-bold">Width</span><input type="number" className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-xs" value={activeContextNode.width} onChange={(e) => onUpdateNode(activeContextNode.id, { width: parseInt(e.target.value) || 200 })} /></div>
              <div className="flex flex-col"><span className="text-[9px] text-slate-400 uppercase font-bold">Height</span><input type="number" className="bg-slate-50 border border-slate-200 rounded px-2 py-1 text-xs" value={activeContextNode.height} onChange={(e) => onUpdateNode(activeContextNode.id, { height: parseInt(e.target.value) || 100 })} /></div>
            </div>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => <button key={c.value} onClick={() => onUpdateNode(activeContextNode.id, { color: c.value })} className={`w-6 h-6 rounded-full border transition-all ${activeContextNode.color === c.value ? 'ring-2 ring-blue-500 ring-offset-1 scale-110 shadow-md' : 'hover:scale-105'}`} style={{ backgroundColor: c.value }} />)}
            </div>
            <button onClick={() => { onDeleteNode(activeContextNode.id); setNodeContextMenu(null); }} className="w-full bg-red-50 text-red-600 text-xs py-2 rounded-lg font-bold hover:bg-red-100 transition-colors">Delete Step</button>
          </div>
        )}

        {slotContextMenu && (
          <div className="fixed z-50 bg-white border border-slate-200 shadow-2xl rounded-xl p-2 w-48 space-y-1" style={{ left: slotContextMenu.x, top: slotContextMenu.y }} onClick={(e) => e.stopPropagation()}>
            <div className="px-2 py-1 flex justify-between items-center mb-1">
              <span className="text-[10px] font-black text-slate-400 uppercase">Task Action</span>
              <button onClick={() => setSlotContextMenu(null)} className="text-slate-400">×</button>
            </div>
            <button 
              onClick={() => deleteSlot(slotContextMenu.nodeId, slotContextMenu.slotId)}
              className="w-full text-left px-3 py-2 text-xs rounded-lg flex items-center gap-2 hover:bg-red-50 text-red-600 transition-colors font-medium"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
              Delete Task
            </button>
          </div>
        )}

        {lineContextMenu && activeContextConn && (
          <div className="fixed z-50 bg-white border border-slate-200 shadow-2xl rounded-xl p-4 w-56 space-y-3" style={{ left: lineContextMenu.x, top: lineContextMenu.y }} onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center text-xs font-black text-slate-400 uppercase tracking-tighter">Connection Type</div>
            <div className="space-y-1">
              {CONNECTION_TYPES.map(ct => (
                <button 
                  key={ct.value}
                  onClick={() => { onUpdateConnection(activeContextConn.id, { type: ct.value }); setLineContextMenu(null); }}
                  className={`w-full text-left px-3 py-2 text-xs rounded-lg flex items-center gap-2 hover:bg-slate-50 transition-colors ${activeContextConn.type === ct.value ? 'bg-blue-50 text-blue-700 font-bold' : 'text-slate-600'}`}
                >
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: ct.color }}></div>
                  {ct.label}
                </button>
              ))}
            </div>
            <div className="border-t pt-2 mt-2">
              <button onClick={() => { onDeleteConnection(activeContextConn.id); setLineContextMenu(null); }} className="w-full bg-slate-50 text-slate-600 text-[11px] py-2 rounded-lg font-bold hover:bg-red-50 hover:text-red-600 transition-colors">Delete Relationship</button>
            </div>
          </div>
        )}
      </div>

      <div className="p-3 bg-white border-t flex justify-between items-center text-xs text-slate-500 z-10">
        <div className="flex gap-4">
          {CONNECTION_TYPES.map(ct => (
            <div key={ct.value} className="flex items-center gap-1">
              <div className="w-3 h-[3px] rounded-full" style={{ backgroundColor: ct.color }}></div> {ct.label}
            </div>
          ))}
        </div>
        <p className="font-medium italic">Right-click steps, tasks, or lines to manage your process architecture • Use the canvas scrollbars to navigate</p>
      </div>
    </div>
  );
};

export default Editor;

import React, { useState, useCallback } from 'react';
import { PageView, ProcessNode, Connection, NodeInsights } from './types';
import Sidebar from './components/Sidebar';
import Editor from './components/Editor';
import Insights from './components/Insights';
import Report from './components/Report';
import Simulation from './components/Simulation';

// Define interface for draft context
interface NodeDraft {
  inputText: string;
  files: File[];
  links: string[];
}

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageView>('editor');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [projectTitle, setProjectTitle] = useState('Process Strategy Master Plan');

  const [nodes, setNodes] = useState<ProcessNode[]>([]);
  const [connections, setConnections] = useState<Connection[]>([]);
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [insightsMap, setInsightsMap] = useState<Record<string, NodeInsights>>({});

  // Store the user inputs/files/links per node
  const [nodeDrafts, setNodeDrafts] = useState<Record<string, NodeDraft>>({});

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const addNode = useCallback((x: number = 100, y: number = 100, layer: number = 0) => {
    const newNode: ProcessNode = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Process Step',
      description: 'Define the objectives for this specific task...',
      x,
      y,
      width: 240,
      height: 120,
      color: '#ffffff',
      slots: [
        { id: Math.random().toString(36).substr(2, 9), label: 'Primary Operation', type: 'task' }
      ],
      layer,
      status: 'idle'
    };
    setNodes(prev => [...prev, newNode]);
    // Initialize draft for the new node with links array
    setNodeDrafts(prev => ({ ...prev, [newNode.id]: { inputText: '', files: [], links: [] } }));
  }, []);

  const updateNode = useCallback((id: string, updates: Partial<ProcessNode>) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, ...updates } : n));
  }, []);

  const deleteNode = useCallback((id: string) => {
    setNodes(prev => prev.filter(n => n.id !== id));
    setConnections(prev => prev.filter(c => c.sourceNodeId !== id && c.targetNodeId !== id));
    setNodeDrafts(prev => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
    if (selectedNodeId === id) setSelectedNodeId(null);
  }, [selectedNodeId]);

  const addConnection = useCallback((conn: Connection) => {
    setConnections(prev => [...prev, conn]);
  }, []);

  const updateConnection = useCallback((id: string, updates: Partial<Connection>) => {
    setConnections(prev => prev.map(c => c.id === id ? { ...c, ...updates } : c));
  }, []);

  const deleteConnection = useCallback((id: string) => {
    setConnections(prev => prev.filter(c => c.id !== id));
  }, []);

  const renderPage = () => {
    switch (activePage) {
      case 'editor':
        return (
          <Editor 
            nodes={nodes} 
            connections={connections} 
            onAddNode={addNode} 
            onUpdateNode={updateNode} 
            onDeleteNode={deleteNode}
            onAddConnection={addConnection}
            onUpdateConnection={updateConnection}
            onDeleteConnection={deleteConnection}
            projectTitle={projectTitle}
            setProjectTitle={setProjectTitle}
            selectedNodeId={selectedNodeId}
            setSelectedNodeId={setSelectedNodeId}
          />
        );
      case 'insights':
        return (
          <Insights 
            nodes={nodes}
            selectedNodeId={selectedNodeId}
            setSelectedNodeId={setSelectedNodeId}
            insightsMap={insightsMap}
            setInsightsMap={setInsightsMap}
            nodeDrafts={nodeDrafts}
            setNodeDrafts={setNodeDrafts}
          />
        );
      case 'simulation':
        return (
          <Simulation 
            nodes={nodes} 
            connections={connections}
            insightsMap={insightsMap}
            setNodes={setNodes}
          />
        );
      case 'report':
        return (
          <Report 
            nodes={nodes} 
            connections={connections} 
            insightsMap={insightsMap}
            projectTitle={projectTitle}
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 text-slate-900 overflow-hidden font-sans">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onToggle={toggleSidebar} 
        activePage={activePage} 
        setActivePage={setActivePage} 
      />

      <main className="flex-1 flex flex-col transition-all duration-300">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-40 shadow-sm">
          <div className="flex items-center gap-4">
            <button 
              onClick={toggleSidebar}
              className="p-2 hover:bg-slate-100 rounded-lg transition-colors border border-transparent hover:border-slate-200"
            >
              <svg className="w-6 h-6 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <h1 className="text-xl font-bold bg-gradient-to-br from-blue-700 to-indigo-700 bg-clip-text text-transparent tracking-tight">
              {projectTitle}
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-700 rounded-full text-xs font-bold border border-emerald-100 shadow-sm">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
              Live Sync
            </div>
            <div className="w-10 h-10 rounded-xl bg-slate-900 overflow-hidden border-2 border-white shadow-lg">
              <img src="https://picsum.photos/40/40?grayscale" alt="User profile" />
            </div>
          </div>
        </header>

        <div className="flex-1 relative overflow-hidden bg-slate-100/50">
          {renderPage()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ProcessNode, NodeInsights } from '../types';
import { analyzeProcessData, GroundingLink } from '../services/geminiService';

interface NodeDraft {
  inputText: string;
  files: File[];
  links: string[];
}

interface InsightsProps {
  nodes: ProcessNode[];
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
  insightsMap: Record<string, NodeInsights>;
  setInsightsMap: React.Dispatch<React.SetStateAction<Record<string, NodeInsights>>>;
  nodeDrafts: Record<string, NodeDraft>;
  setNodeDrafts: React.Dispatch<React.SetStateAction<Record<string, NodeDraft>>>;
}

const Insights: React.FC<InsightsProps> = ({ 
  nodes, 
  selectedNodeId, 
  setSelectedNodeId, 
  insightsMap, 
  setInsightsMap,
  nodeDrafts,
  setNodeDrafts
}) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [currentLinks, setCurrentLinks] = useState<GroundingLink[]>([]);
  const [lastResponseText, setLastResponseText] = useState<string>('');
  const [linkInput, setLinkInput] = useState('');

  const currentNode = nodes.find(n => n.id === selectedNodeId);

  // Get draft for the selected node or default empty
  const currentDraft = selectedNodeId ? nodeDrafts[selectedNodeId] || { inputText: '', files: [], links: [] } : { inputText: '', files: [], links: [] };

  const updateDraftText = (text: string) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: { ...prev[selectedNodeId], inputText: text }
    }));
  };

  const addLink = () => {
    if (!selectedNodeId || !linkInput.trim()) return;
    const url = linkInput.trim().startsWith('http') ? linkInput.trim() : `https://${linkInput.trim()}`;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: { 
        ...prev[selectedNodeId], 
        links: [...(prev[selectedNodeId]?.links || []), url] 
      }
    }));
    setLinkInput('');
  };

  const removeLink = (index: number) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: {
        ...prev[selectedNodeId],
        links: (prev[selectedNodeId]?.links || []).filter((_, i) => i !== index)
      }
    }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && selectedNodeId) {
      const newFiles = Array.from(e.target.files);
      setNodeDrafts(prev => ({
        ...prev,
        [selectedNodeId]: { ...prev[selectedNodeId], files: [...prev[selectedNodeId].files, ...newFiles] }
      }));
    }
  };

  const removeFile = (index: number) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: {
        ...prev[selectedNodeId],
        files: prev[selectedNodeId].files.filter((_, i) => i !== index)
      }
    }));
  };

  const handleAnalyze = async () => {
    if (!currentNode || !selectedNodeId) return;
    setIsAnalyzing(true);

    const fileContext = currentDraft.files.map(f => f.name).join(', ');
    const linkContext = (currentDraft.links || []).join(', ');
    const rawContext = `
      Target Node: ${currentNode.title}
      Description: ${currentNode.description}
      Files Provided: ${fileContext || 'None'}
      External Reference Links: ${linkContext || 'None'}
      User Input Context: ${currentDraft.inputText}
    `;

    let location = undefined;
    try {
      if ('geolocation' in navigator) {
        const pos = await new Promise<GeolocationPosition>((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));
        location = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
      }
    } catch (e) { console.debug("Location restricted"); }

    const result = await analyzeProcessData(currentNode.title, rawContext, currentDraft.inputText || "Analyze this process step considering all files and reference links provided.", location);

    if (result) {
      setLastResponseText(result.text);
      setCurrentLinks(result.links);

      setInsightsMap(prev => ({
        ...prev,
        [selectedNodeId]: { 
          nodeId: selectedNodeId, 
          summary: result.text, 
          requirements: [], 
          resources: [], 
          executionStyle: 'Standard' 
        }
      }));
    }
    setIsAnalyzing(false);
  };

  const StepSelector = () => (
    <div className="flex items-center gap-3 bg-white border border-slate-200 rounded-xl px-4 py-2 shadow-sm">
      <label htmlFor="step-select" className="text-xs font-bold text-slate-400 uppercase tracking-tight">Active Node:</label>
      <select 
        id="step-select"
        value={selectedNodeId || ''}
        onChange={(e) => {
          setSelectedNodeId(e.target.value || null);
          setLastResponseText('');
          setCurrentLinks([]);
        }}
        className="bg-transparent text-sm font-bold text-slate-800 focus:outline-none cursor-pointer min-w-[200px]"
      >
        <option value="">-- Choose Target Node --</option>
        {nodes.map(node => (
          <option key={node.id} value={node.id}>
            {node.title || 'Untitled Step'}
          </option>
        ))}
      </select>
    </div>
  );

  if (!selectedNodeId && nodes.length > 0) {
    return (
      <div className="h-full flex flex-col p-6 space-y-6">
        <div className="flex items-center justify-between border-b pb-4">
           <h2 className="text-2xl font-bold text-slate-800">Process Insights</h2>
           <StepSelector />
        </div>
        <div className="flex-1 flex items-center justify-center text-slate-400 flex-col gap-4 bg-white rounded-2xl border border-dashed border-slate-200">
          <svg className="w-16 h-16 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          <div className="text-center">
            <p className="text-lg font-medium text-slate-600">Contextual Data Mapping</p>
            <p className="text-sm">Select a step to upload files, enter text, or provide reference links.</p>
          </div>
        </div>
      </div>
    );
  }

  const currentInsights = selectedNodeId ? insightsMap[selectedNodeId] : null;

  return (
    <div className="h-full flex flex-col p-6 space-y-6 overflow-auto">
      <div className="flex items-center justify-between border-b pb-4 sticky top-0 bg-slate-50/90 backdrop-blur-md z-10">
        <div className="flex flex-col">
          <h2 className="text-2xl font-bold text-slate-800 tracking-tight">Step Intelligence</h2>
          <p className="text-slate-500 text-xs">Matching Context to: <span className="text-blue-600 font-bold uppercase">{currentNode?.title}</span></p>
        </div>

        <div className="flex items-center gap-4">
          <StepSelector />
          <button 
            onClick={handleAnalyze}
            disabled={isAnalyzing || !selectedNodeId}
            className="px-6 py-2 bg-slate-900 text-white rounded-xl font-bold hover:bg-black disabled:opacity-50 flex items-center gap-2 transition-all shadow-lg active:scale-95"
          >
            {isAnalyzing ? (
              <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
            ) : 'Deep Analysis'}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 pb-10">
        <div className="space-y-4">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-6">
            <h3 className="font-bold flex items-center gap-2 text-slate-800">
              <div className="w-8 h-8 rounded-lg bg-blue-50 flex items-center justify-center">
                <svg className="w-4 h-4 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </div>
              Isolated Step Context: {currentNode?.title}
            </h3>

            <div className="space-y-2">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Manual Specifications</p>
              <textarea 
                value={currentDraft.inputText}
                onChange={(e) => updateDraftText(e.target.value)}
                placeholder={`Technical constraints for ${currentNode?.title}...`}
                className="w-full h-32 p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all resize-none outline-none"
              />
            </div>

            <div className="space-y-2">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Contextual Links</p>
              <div className="flex gap-2">
                <input 
                  type="text"
                  value={linkInput}
                  onChange={(e) => setLinkInput(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && addLink()}
                  placeholder="Paste URL (specs, benchmarks, etc.)"
                  className="flex-1 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:border-blue-400"
                />
                <button 
                  onClick={addLink}
                  className="px-4 py-2 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200 transition-colors"
                >
                  Add
                </button>
              </div>
              {currentDraft.links && currentDraft.links.length > 0 && (
                <div className="flex flex-wrap gap-2 pt-2">
                  {currentDraft.links.map((link, i) => (
                    <div key={i} className="flex items-center gap-2 bg-blue-50 border border-blue-100 px-3 py-1 rounded-full text-[10px] text-blue-700 font-bold group animate-in zoom-in-50">
                      <span className="truncate max-w-[200px]">{link}</span>
                      <button onClick={() => removeLink(i)} className="text-blue-300 hover:text-red-500"><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="space-y-2">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Supporting Documents</p>
              <div className="border-2 border-dashed border-slate-200 rounded-xl p-6 text-center hover:bg-slate-50 hover:border-blue-300 transition-all cursor-pointer relative group">
                <input type="file" multiple onChange={handleFileUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
                <p className="text-sm font-bold text-slate-600">Drop Step Blueprint</p>
              </div>
              {currentDraft.files.length > 0 && (
                <div className="max-h-32 overflow-auto space-y-2 pr-1 pt-2">
                  {currentDraft.files.map((file, i) => (
                    <div key={i} className="flex items-center justify-between bg-slate-50 border border-slate-100 p-2 px-3 rounded-lg text-[11px] animate-in slide-in-from-left-2">
                      <span className="truncate font-medium text-slate-700">{file.name}</span>
                      <button onClick={() => removeFile(i)} className="text-slate-300 hover:text-red-500 transition-colors"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="space-y-4">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm min-h-[400px]">
            <h3 className="font-bold mb-4 flex items-center gap-2 text-slate-800">
               <div className="w-8 h-8 rounded-lg bg-emerald-50 flex items-center justify-center">
                <svg className="w-4 h-4 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              </div>
              Analysis Output: {currentNode?.title}
            </h3>

            {!lastResponseText && !currentInsights ? (
              <div className="flex flex-col items-center justify-center h-64 text-slate-300 space-y-3">
                <div className="w-12 h-12 rounded-full border-2 border-slate-100 border-t-emerald-400 animate-spin"></div>
                <p className="text-sm font-medium">Ready to process Contextual Links & Files...</p>
              </div>
            ) : (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
                <div className="bg-slate-50 border border-slate-100 p-4 rounded-xl prose prose-slate max-w-none text-slate-700 text-sm leading-relaxed">
                  {(lastResponseText || currentInsights?.summary || '').split('\n').map((line, i) => (
                    <p key={i} className="mb-2">{line}</p>
                  ))}
                </div>

                {currentLinks.length > 0 && (
                  <div className="pt-4 border-t border-slate-100">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Grounding Sources</h4>
                    <div className="grid grid-cols-1 gap-2">
                      {currentLinks.map((link, i) => (
                        <a 
                          key={i} 
                          href={link.uri} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="flex items-center gap-3 p-3 bg-blue-50 border border-blue-100 rounded-xl hover:bg-blue-100 transition-all text-blue-700 hover:translate-x-1"
                        >
                          <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                          <span className="text-xs font-bold truncate">{link.title || link.uri}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Insights;

import React, { useState, useEffect } from 'react';
import { ProcessNode, NodeInsights, Connection } from '../types';
import { analyzeProcessData, GroundingLink } from '../services/geminiService';

interface NodeDraft {
  inputText: string;
  files: File[];
  links: string[];
}

interface InsightsProps {
  nodes: ProcessNode[];
  connections: Connection[];
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
  insightsMap: Record<string, NodeInsights>;
  setInsightsMap: React.Dispatch<React.SetStateAction<Record<string, NodeInsights>>>;
  nodeDrafts: Record<string, NodeDraft>;
  setNodeDrafts: React.Dispatch<React.SetStateAction<Record<string, NodeDraft>>>;
}

const Insights: React.FC<InsightsProps> = ({ 
  nodes, 
  connections,
  selectedNodeId, 
  setSelectedNodeId, 
  insightsMap, 
  setInsightsMap,
  nodeDrafts,
  setNodeDrafts
}) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [currentLinks, setCurrentLinks] = useState<GroundingLink[]>([]);
  const [lastResponseText, setLastResponseText] = useState<string>('');
  const [linkInput, setLinkInput] = useState('');

  const currentNode = nodes.find(n => n.id === selectedNodeId);

  const currentDraft = selectedNodeId ? nodeDrafts[selectedNodeId] || { inputText: '', files: [], links: [] } : { inputText: '', files: [], links: [] };

  const updateDraftText = (text: string) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: { ...prev[selectedNodeId], inputText: text }
    }));
  };

  const addLink = () => {
    if (!selectedNodeId || !linkInput.trim()) return;
    const url = linkInput.trim().startsWith('http') ? linkInput.trim() : `https://${linkInput.trim()}`;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: { 
        ...prev[selectedNodeId], 
        links: [...(prev[selectedNodeId]?.links || []), url] 
      }
    }));
    setLinkInput('');
  };

  const removeLink = (index: number) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: {
        ...prev[selectedNodeId],
        links: (prev[selectedNodeId]?.links || []).filter((_, i) => i !== index)
      }
    }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && selectedNodeId) {
      const newFiles = Array.from(e.target.files);
      setNodeDrafts(prev => ({
        ...prev,
        [selectedNodeId]: { ...prev[selectedNodeId], files: [...prev[selectedNodeId].files, ...newFiles] }
      }));
    }
  };

  const removeFile = (index: number) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: {
        ...prev[selectedNodeId],
        files: prev[selectedNodeId].files.filter((_, i) => i !== index)
      }
    }));
  };

  const handleAnalyze = async () => {
    if (!currentNode || !selectedNodeId) return;
    setIsAnalyzing(true);

    // 1. GATHER UPSTREAM DEPENDENCY CONSTRAINTS
    const upstreamConnections = connections.filter(c => c.targetNodeId === selectedNodeId);
    const dependencyContext = upstreamConnections.map(conn => {
      const sourceNode = nodes.find(n => n.id === conn.sourceNodeId);
      const sourceInsights = insightsMap[conn.sourceNodeId];
      return `
        DEPENDENCY FROM: ${sourceNode?.title || 'Unknown Step'}
        RELATIONSHIP TYPE: ${conn.type}
        SOURCE DESCRIPTION: ${sourceNode?.description || 'No description'}
        SOURCE REQUIREMENTS/OUTPUTS: ${sourceInsights?.summary || 'Not yet analyzed'}
      `;
    }).join('\n---\n');

    // 2. CONSTRUCT COMPREHENSIVE CONTEXT
    const fileContext = currentDraft.files.map(f => f.name).join(', ');
    const linkContext = (currentDraft.links || []).join(', ');

    const rawContext = `
      TARGET NODE: ${currentNode.title}
      TARGET DESCRIPTION: ${currentNode.description}

      RELATIONSHIP CONSTRAINTS (UPSTREAM DEPENDENCIES):
      ${dependencyContext || 'No direct upstream dependencies identified.'}

      SPECIFIC FILES PROVIDED: ${fileContext || 'None'}
      REFERENCE LINKS: ${linkContext || 'None'}
      USER NOTES: ${currentDraft.inputText}
    `;

    const prompt = `Analyze this process step. IMPORTANT: You must ensure this step aligns with the RELATIONSHIP CONSTRAINTS provided. If an upstream step has requirements, explain how this step fulfills or consumes those outputs. Provide technical requirements, resource needs, and a summary of execution strategy.`;

    let location = undefined;
    try {
      if ('geolocation' in navigator) {
        const pos = await new Promise<GeolocationPosition>((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));
        location = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
      }
    } catch (e) { console.debug("Location restricted"); }

    const result = await analyzeProcessData(currentNode.title, rawContext, prompt, location);

    if (result) {
      setLastResponseText(result.text);
      setCurrentLinks(result.links);

      setInsightsMap(prev => ({
        ...prev,
        [selectedNodeId]: { 
          nodeId: selectedNodeId, 
          summary: result.text, 
          requirements: [], 
          resources: [], 
          executionStyle: 'Standard' 
        }
      }));
    }
    setIsAnalyzing(false);
  };

  const StepSelector = () => (
    <div className="flex items-center gap-3 bg-white border border-slate-200 rounded-xl px-4 py-2 shadow-sm">
      <label htmlFor="step-select" className="text-xs font-bold text-slate-400 uppercase tracking-tight">Active Node:</label>
      <select 
        id="step-select"
        value={selectedNodeId || ''}
        onChange={(e) => {
          setSelectedNodeId(e.target.value || null);
          setLastResponseText('');
          setCurrentLinks([]);
        }}
        className="bg-transparent text-sm font-bold text-slate-800 focus:outline-none cursor-pointer min-w-[200px]"
      >
        <option value="">-- Choose Target Node --</option>
        {nodes.map(node => (
          <option key={node.id} value={node.id}>
            {node.title || 'Untitled Step'}
          </option>
        ))}
      </select>
    </div>
  );

  if (!selectedNodeId && nodes.length > 0) {
    return (
      <div className="h-full flex flex-col p-6 space-y-6">
        <div className="flex items-center justify-between border-b pb-4">
           <h2 className="text-2xl font-bold text-slate-800 tracking-tight">Process Intelligence</h2>
           <StepSelector />
        </div>
        <div className="flex-1 flex items-center justify-center text-slate-400 flex-col gap-4 bg-white rounded-2xl border border-dashed border-slate-200 shadow-inner">
          <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center border border-slate-100 mb-2">
            <svg className="w-8 h-8 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
          </div>
          <div className="text-center">
            <p className="text-lg font-bold text-slate-600">Select Step to Analyze</p>
            <p className="text-sm max-w-xs mx-auto">The system will automatically link upstream dependencies to ensure cross-process consistency.</p>
          </div>
        </div>
      </div>
    );
  }

  const currentInsights = selectedNodeId ? insightsMap[selectedNodeId] : null;

  return (
    <div className="h-full flex flex-col p-6 space-y-6 overflow-auto">
      <div className="flex items-center justify-between border-b pb-4 sticky top-0 bg-slate-50/90 backdrop-blur-md z-10">
        <div className="flex flex-col">
          <h2 className="text-2xl font-black text-slate-800 tracking-tighter">Step Intelligence</h2>
          <div className="flex items-center gap-2">
            <span className="text-[10px] bg-blue-600 text-white px-1.5 py-0.5 rounded font-black uppercase">Active Context</span>
            <p className="text-blue-600 text-xs font-bold uppercase">{currentNode?.title}</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <StepSelector />
          <button 
            onClick={handleAnalyze}
            disabled={isAnalyzing || !selectedNodeId}
            className="px-6 py-2 bg-slate-900 text-white rounded-xl font-black hover:bg-black disabled:opacity-50 flex items-center gap-3 transition-all shadow-xl active:scale-95 group"
          >
            {isAnalyzing ? (
              <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
            ) : (
              <>
                <svg className="w-5 h-5 text-blue-400 group-hover:rotate-12 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                DEEP ANALYSIS
              </>
            )}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 pb-10">
        <div className="space-y-4">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="font-bold flex items-center gap-2 text-slate-800">
                <div className="w-8 h-8 rounded-lg bg-blue-50 flex items-center justify-center">
                  <svg className="w-4 h-4 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                </div>
                Isolated Step Data
