                <span className="text-[9px] font-black text-slate-500 uppercase">Context Encrypted</span>
              </div>
            </div>

            <div className="space-y-2">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Technical Specifications</p>
              <textarea 
                value={currentDraft.inputText}
                onChange={(e) => updateDraftText(e.target.value)}
                placeholder={`What are the specific constraints for ${currentNode?.title}?`}
                className="w-full h-32 p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all resize-none outline-none font-medium"
              />
            </div>

            <div className="space-y-2">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Knowledge Base Links</p>
              <div className="flex gap-2">
                <input 
                  type="text"
                  value={linkInput}
                  onChange={(e) => setLinkInput(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && addLink()}
                  placeholder="Reference URL (e.g. standards, suppliers)"
                  className="flex-1 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:border-blue-400 transition-all"
