import { GoogleGenAI } from "@google/genai";

export interface GroundingLink {
  uri: string;
  title: string;
}

export const analyzeProcessData = async (
  nodeTitle: string, 
  rawText: string, 
  userPrompt: string, 
  location?: { latitude: number, longitude: number }
) => {
  // Fix: Client must be initialized with a named parameter
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Decide model: Maps grounding requires 2.5 series
  const isMapsQuery = userPrompt.toLowerCase().includes('near') || 
                      userPrompt.toLowerCase().includes('map') || 
                      userPrompt.toLowerCase().includes('location');

  // Fix: Use correct model names; gemini-2.5-flash for maps grounding and gemini-3-flash-preview for general text
  const modelName = isMapsQuery ? 'gemini-2.5-flash' : 'gemini-3-flash-preview';

  const systemInstruction = `You are system analyzer and a Planner. 
  Your task is to analyze process steps and provide data-driven insights. 
  If external information is needed (costs, suppliers, standards), use the Search tool. 
  If geographic information is needed, use the Maps tool. 
  Always link specific contextual data provided by the user to the step "${nodeTitle}".`;

  const contents = `
    STEP TITLE: ${nodeTitle}
    CONTEXT DATA & FILES PROVIDED: ${rawText}
    USER REQUEST: ${userPrompt}
  `;

  // Fix: Ensure correct tool combination according to grounding rules
  const tools: any[] = isMapsQuery ? [{ googleSearch: {} }, { googleMaps: {} }] : [{ googleSearch: {} }];

  try {
    // Fix: Using correct contents structure and property access for the text output
    const response = await ai.models.generateContent({
      model: modelName,
      contents: contents,
      config: {
        systemInstruction,
        tools,
        toolConfig: location ? {
          retrievalConfig: {
            latLng: {
              latitude: location.latitude,
              longitude: location.longitude
            }
          }
        } : undefined
      }
    });

    const text = response.text || '';

    // Extract grounding links from chunks
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links: GroundingLink[] = [];

    groundingChunks.forEach((chunk: any) => {
      if (chunk.web) {
        links.push({ uri: chunk.web.uri, title: chunk.web.title });
      } else if (chunk.maps) {
        links.push({ uri: chunk.maps.uri, title: chunk.maps.title });
      }
    });

    return {
      text,
      links: Array.from(new Set(links.map(l => JSON.stringify(l)))).map(s => JSON.parse(s)) as GroundingLink[]
    };
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return null;
  }
};

export type SlotType = 'task' | 'decision' | 'operation';
export type ConnectionType = 'dependency' | 'data-flow' | 'resource-flow' | 'informational';

export interface ProcessSlot {
  id: string;
  label: string;
  type: SlotType;
}

export interface ProcessNode {
  id: string;
  title: string;
  description: string;
  x: number;
  y: number;
  width: number;
  height: number;
  color: string;
  slots: ProcessSlot[];
  layer: number; // For horizontal positioning
  status: 'idle' | 'running' | 'success' | 'failed';
}

export interface Connection {
  id: string;
  sourceNodeId: string;
  sourceSlotId: string;
  targetNodeId: string;
  targetSlotId: string;
