                  log.includes('[DATA]') ? 'text-blue-200 italic' : 
                  log.includes('[VALIDATING]') ? 'text-amber-400 font-black' : 'text-slate-400'
                }`}>
                  {log}
                </span>
              </div>
            ))}
            {isRunning && (
              <div className="flex items-center gap-2 text-blue-400/50 animate-pulse mt-2">
                <span className="w-2 h-2 bg-blue-400 rounded-full"></span>
                <span className="font-black uppercase tracking-tighter">Streaming Relational Data...</span>
              </div>
            )}
          </div>

          <div className="mt-6 pt-4 border-t border-slate-800 flex justify-between items-center text-[9px] font-black text-slate-500">
             <span>SYS_CLUSTER: ALPHA_01</span>
             <span>BUFFER: 4096KB</span>
          </div>
        </div>
      </div>
    </div>
  );
};

