import { GoogleGenAI, Type } from "@google/genai";

export interface GroundingLink {
  uri: string;
  title: string;
}

export const analyzeProcessData = async (
  nodeTitle: string, 
  rawText: string, 
  userPrompt: string, 
  location?: { latitude: number, longitude: number }
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const isMapsQuery = userPrompt.toLowerCase().includes('near') || 
                      userPrompt.toLowerCase().includes('map') || 
                      userPrompt.toLowerCase().includes('location');

  const modelName = isMapsQuery ? 'gemini-2.5-flash' : 'gemini-3-flash-preview';

  const systemInstruction = `You are a Process Intelligence Analyst. 
  Your task is to analyze process steps and provide structured, data-driven insights. 

  CRITICAL: You must calculate a "comparison_weight" (float, max 3.0) based on the following formula:
  weight = (number of pre-defined tasks in slots / number of instructions in your generated strategy) 
         + (number of resources identified in user data / total resources identified as needed) 
         + (number of tasks mentioned as 'done' or 'ready' in user notes / number of instructions in your generated strategy).

  Provide a summary of execution strategy and a list of required resources with estimated costs.
  If external information is needed, use the Search tool. If geographic information is needed, use the Maps tool.`;

  const contents = `
    STEP TITLE: ${nodeTitle}
    CONTEXT DATA & USER NOTES: ${rawText}
    USER REQUEST: ${userPrompt}
  `;

  const tools: any[] = isMapsQuery ? [{ googleSearch: {} }, { googleMaps: {} }] : [{ googleSearch: {} }];

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: contents,
      config: {
        systemInstruction,
        tools,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "A detailed summary of the execution strategy." },
            comparison_weight: { type: Type.NUMBER, description: "The calculated alignment metric (max 3.0)." },
            resources: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  type: { type: Type.STRING },
                  cost: { type: Type.NUMBER },
                  available: { type: Type.BOOLEAN }
                },
                required: ["name", "type", "cost", "available"]
              }
            }
          },
          required: ["summary", "comparison_weight", "resources"]
        },
        toolConfig: location ? {
          retrievalConfig: {
            latLng: {
              latitude: location.latitude,
              longitude: location.longitude
            }
          }
        } : undefined
      }
    });

    const jsonStr = response.text || '{}';
    const parsed = JSON.parse(jsonStr);

    // Extract grounding links from chunks
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links: GroundingLink[] = [];

    groundingChunks.forEach((chunk: any) => {
      if (chunk.web) {
        links.push({ uri: chunk.web.uri, title: chunk.web.title });
      } else if (chunk.maps) {
        links.push({ uri: chunk.maps.uri, title: chunk.maps.title });
      }
    });

    return {
      summary: parsed.summary,
      resources: parsed.resources,
      comparison_weight: parsed.comparison_weight,
      links: Array.from(new Set(links.map(l => JSON.stringify(l)))).map(s => JSON.parse(s)) as GroundingLink[]
    };
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return null;
  }
};

import React, { useState } from 'react';
import { ProcessNode, NodeInsights, Connection, Resource } from '../types';
import { analyzeProcessData, GroundingLink } from '../services/geminiService';

interface NodeDraft {
  inputText: string;
  files: File[];
  links: string[];
}

interface InsightsProps {
  nodes: ProcessNode[];
  connections: Connection[];
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;
  insightsMap: Record<string, NodeInsights>;
  setInsightsMap: React.Dispatch<React.SetStateAction<Record<string, NodeInsights>>>;
  nodeDrafts: Record<string, NodeDraft>;
  setNodeDrafts: React.Dispatch<React.SetStateAction<Record<string, NodeDraft>>>;
}

const Insights: React.FC<InsightsProps> = ({ 
  nodes, 
  connections,
  selectedNodeId, 
  setSelectedNodeId, 
  insightsMap, 
  setInsightsMap,
  nodeDrafts,
  setNodeDrafts
}) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [currentLinks, setCurrentLinks] = useState<GroundingLink[]>([]);
  const [lastResponseText, setLastResponseText] = useState<string>('');
  const [linkInput, setLinkInput] = useState('');

  const currentNode = nodes.find(n => n.id === selectedNodeId);
  const currentDraft = selectedNodeId ? nodeDrafts[selectedNodeId] || { inputText: '', files: [], links: [] } : { inputText: '', files: [], links: [] };

  const updateDraftText = (text: string) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: { ...prev[selectedNodeId], inputText: text }
    }));
  };

  const addLink = () => {
    if (!selectedNodeId || !linkInput.trim()) return;
    const url = linkInput.trim().startsWith('http') ? linkInput.trim() : `https://${linkInput.trim()}`;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: { 
        ...prev[selectedNodeId], 
        links: [...(prev[selectedNodeId]?.links || []), url] 
      }
    }));
    setLinkInput('');
  };

  const removeLink = (index: number) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: {
        ...prev[selectedNodeId],
        links: (prev[selectedNodeId]?.links || []).filter((_, i) => i !== index)
      }
    }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && selectedNodeId) {
      const newFiles = Array.from(e.target.files);
      setNodeDrafts(prev => ({
        ...prev,
        [selectedNodeId]: { ...prev[selectedNodeId], files: [...prev[selectedNodeId].files, ...newFiles] }
      }));
    }
  };

  const removeFile = (index: number) => {
    if (!selectedNodeId) return;
    setNodeDrafts(prev => ({
      ...prev,
      [selectedNodeId]: {
        ...prev[selectedNodeId],
        files: prev[selectedNodeId].files.filter((_, i) => i !== index)
      }
    }));
  };

  const handleAnalyze = async () => {
    if (!currentNode || !selectedNodeId) return;
    setIsAnalyzing(true);

    const upstreamConnections = connections.filter(c => c.targetNodeId === selectedNodeId);
    const dependencyContext = upstreamConnections.map(conn => {
      const sourceNode = nodes.find(n => n.id === conn.sourceNodeId);
      const sourceInsights = insightsMap[conn.sourceNodeId];
      return `
        DEPENDENCY FROM: ${sourceNode?.title || 'Unknown Step'}
        RELATIONSHIP TYPE: ${conn.type}
        SOURCE DESCRIPTION: ${sourceNode?.description || 'No description'}
        SOURCE REQUIREMENTS/OUTPUTS: ${sourceInsights?.summary || 'Not yet analyzed'}
      `;
    }).join('\n---\n');

    const fileContext = currentDraft.files.map(f => f.name).join(', ');
    const linkContext = (currentDraft.links || []).join(', ');
    const slotContext = currentNode.slots.map(s => `- ${s.label} (${s.type})`).join('\n');

    const rawContext = `
      TARGET NODE: ${currentNode.title}
      TARGET DESCRIPTION: ${currentNode.description}

      TARGET SLOTS (TASKS/OPS):
      ${slotContext || 'No specific task slots defined.'}

      RELATIONSHIP CONSTRAINTS (UPSTREAM DEPENDENCIES):
      ${dependencyContext || 'No direct upstream dependencies identified.'}

      SPECIFIC FILES PROVIDED: ${fileContext || 'None'}
      REFERENCE LINKS: ${linkContext || 'None'}
      USER NOTES: ${currentDraft.inputText}
    `;

    const prompt = `Analyze this process step. 
    1. Evaluate how the TARGET SLOTS (tasks/ops) fit into the execution strategy.
    2. Identify resources needed.
    3. Calculate the comparison_weight based on input data vs generated strategy.
    4. Ensure alignment with RELATIONAL CONSTRAINTS from predecessors.`;

    let location = undefined;
    try {
      if ('geolocation' in navigator) {
        const pos = await new Promise<GeolocationPosition>((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));
        location = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
      }
    } catch (e) { console.debug("Location restricted"); }

    const result = await analyzeProcessData(currentNode.title, rawContext, prompt, location);

    if (result) {
      setLastResponseText(result.summary);
      setCurrentLinks(result.links);

